#!/usr/bin/env python3
"""
V2: Iterative improvement on martian benchmark.
Caches diffs to avoid re-fetching. Supports multiple prompt strategies.

Usage:
    python benchmarks/martian_bench_v2.py review --strategy precise
    python benchmarks/martian_bench_v2.py review --strategy two_pass
    python benchmarks/martian_bench_v2.py judge
"""

