def extract_pr_info(url: str) -> tuple[str, int] | None:
    parts = url.rstrip("/").split("/")
    try:
        pull_idx = parts.index("pull")
        owner_repo = f"{parts[pull_idx - 2]}/{parts[pull_idx - 1]}"
        pr_number = int(parts[pull_idx + 1])
        return owner_repo, pr_number
    except (ValueError, IndexError):
        return None


def fetch_pr_diff(owner_repo: str, pr_number: int) -> str | None:
    try:
        result = subprocess.run(
            ["gh", "api", f"repos/{owner_repo}/pulls/{pr_number}",
             "-H", "Accept: application/vnd.github.v3.diff"],
            capture_output=True, text=True, timeout=30,
        )
        if result.returncode != 0:
            return None
        return result.stdout
    except subprocess.TimeoutExpired:
        return None


def truncate_diff(diff: str, max_chars: int = 20000) -> str:
    """Truncate diff keeping most important files. Larger window than v1."""
    if len(diff) <= max_chars:
        return diff

    files = diff.split("diff --git ")
    if not files:
        return diff[:max_chars]

    scored = []
    for f in files:
        if not f.strip():
            continue
        adds = f.count("\n+") - f.count("\n+++")
        dels = f.count("\n-") - f.count("\n---")
        # Prefer files with both adds and deletes (modifications) over pure adds/deletes
        mod_bonus = min(adds, dels) * 2
        score = adds + dels + mod_bonus

        # Deprioritize test files, docs, configs, snapshots
        first_line = f.split("\n")[0].lower()
        if any(kw in first_line for kw in ["test", "spec", "mock", "__test__", "fixture"]):
            score = score * 0.3
        if any(kw in first_line for kw in [".md", ".adoc", ".txt", ".rst", "changelog", "readme"]):
            score = score * 0.2
        if any(kw in first_line for kw in [".snap", ".lock", "package-lock", "yarn.lock"]):
            score = score * 0.1
        if any(kw in first_line for kw in [".json", ".yaml", ".yml", ".toml", ".xml"]):
            score = score * 0.5

        scored.append((score, f))

    scored.sort(key=lambda x: x[0], reverse=True)

    result = ""
    for _, f in scored:
        candidate = "diff --git " + f
        if len(result) + len(candidate) > max_chars:
            break
        result += candidate

    return result if result else diff[:max_chars]


def build_triage_section(entities: list[dict]) -> str:
    if not entities:
        return ""

    file_risks = {}
    for e in entities:
        fp = e.get("file_path", "")
        score = e.get("risk_score", 0)
        if fp not in file_risks or score > file_risks[fp]:
            file_risks[fp] = score

    top_files = sorted(file_risks.items(), key=lambda x: x[1], reverse=True)[:10]
    if not top_files:
        return ""

    lines = ["Entity-level risk triage (focus review on these files):"]
    for fp, score in top_files:
        lines.append(f"  - {fp} (risk: {score:.2f})")
    return "\n".join(lines)


def build_rich_triage(entities: list[dict]) -> str:
    """Build a richer triage section with entity details, not just file scores."""
    if not entities:
        return ""

    # Filter to modified/added entities with meaningful types
    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)]
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
    top = meaningful[:20]

    if not top:
        return build_triage_section(entities)

    # Group by file
    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    lines = ["## Entity-level triage (highest-risk changes):"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        lines.append(f"\n**{fp}**:")
        for e in ents:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            public = " [PUBLIC API]" if e.get("is_public_api") else ""
            lines.append(f"  - {name} ({etype}, {change}, {classification}){public}")

    return "\n".join(lines)


def build_entity_annotations(entities: list[dict], budget: int = 6000) -> str:
    """Build compact entity annotations with graph metadata: risk, blast radius, dependents, dependencies.
    This goes alongside the raw diff to tell the LLM where to look hardest."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added", "deleted")]
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)

    # Skip parent entities when children exist in the same file
    parent_types = {"class", "interface", "struct", "module", "impl"}
    by_file_types = {}
    for e in meaningful:
        fp = e.get("file_path", "")
        by_file_types.setdefault(fp, set()).add(e.get("entity_type", ""))

    filtered = []
    for e in meaningful:
        fp = e.get("file_path", "")
        etype = e.get("entity_type", "")
        file_types = by_file_types.get(fp, set())
        if etype in parent_types and (file_types - parent_types - {"chunk"}):
            continue
        filtered.append(e)

    by_file = {}
    for e in filtered:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    total_chars = 0
    lines = ["## Semantic analysis (entities by risk, with dependency graph):"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        if total_chars >= budget:
            break
        file_line = f"\n### {fp}"
        lines.append(file_line)
        total_chars += len(file_line)

        for e in sorted(ents, key=lambda e: e.get("risk_score", 0), reverse=True):
            if total_chars >= budget:
                break
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            risk = e.get("risk_score", 0)
            blast = e.get("blast_radius", 0)
            dep_count = e.get("dependent_count", 0)
            dep_names = e.get("dependent_names", [])
            dependency_names = e.get("dependency_names", [])
            public = " PUBLIC_API" if e.get("is_public_api") else ""

            parts = [f"- `{name}` ({etype}, {change}) risk={risk:.2f} blast={blast}"]
            if public:
                parts[0] += public
            if dep_count > 0 and dep_names:
                # dep_names can be [["name", "file"], ...] or ["name", ...]
                top_deps = dep_names[:5]
                dep_str = ", ".join(d[0] if isinstance(d, list) else d for d in top_deps)
                if dep_count > 5:
                    dep_str += f" (+{dep_count - 5} more)"
                parts.append(f"  Used by: {dep_str}")
            if dependency_names:
                top_calls = dependency_names[:5]
                call_str = ", ".join(d[0] if isinstance(d, list) else d for d in top_calls)
                if len(dependency_names) > 5:
                    call_str += f" (+{len(dependency_names) - 5} more)"
                parts.append(f"  Calls: {call_str}")

            entry = "\n".join(parts)
            lines.append(entry)
            total_chars += len(entry)

    return "\n".join(lines)


def build_rich_triage_v29(entities: list[dict]) -> str:
    """Lean triage ~2K chars. 20 entities, name/type/change/classification only."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)
                  and not (e.get("structural_change") == False)]  # skip cosmetic
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
    top = meaningful[:20]

    if not top:
        return build_triage_section(entities)

    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    lines = ["## Entity-level triage (highest-risk changes):"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        lines.append(f"\n**{fp}**:")
        for e in ents:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            public = " [PUBLIC API]" if e.get("is_public_api") else ""
            lines.append(f"  - {name} ({etype}, {change}, {classification}){public}")

    return "\n".join(lines)


def build_dep_cache(benchmark: dict, diff_cache: dict) -> dict:
    """Run sem graph on all changed files for each PR. Returns {pr_url: {entity_name: {dependents: [...], dependencies: [...], dep_count: N}}}."""
    import re as _re

    cache_path = DEP_CACHE
    if cache_path.exists():
        with open(cache_path) as f:
            return json.load(f)

    if not SEM_BIN.exists():
        print(f"sem binary not found at {SEM_BIN}")
        return {}

    if not REPOS_DIR.exists():
        print(f"Repos not found at {REPOS_DIR}")
        return {}

    dep_cache = {}
    supported_exts = {".java", ".py", ".go", ".ts", ".tsx", ".js", ".jsx", ".rs", ".rb", ".c", ".cpp", ".cs", ".kt", ".scala"}

    for url, entry in benchmark.items():
        parts = url.split("/")
        owner_repo = parts[3] + "/" + parts[4]
        pr_number = parts[6]
        repo_dir_name = REPO_DIR_MAP.get(owner_repo)
        if not repo_dir_name:
            dep_cache[url] = {}
            continue

        repo_path = REPOS_DIR / repo_dir_name
        if not repo_path.exists():
            dep_cache[url] = {}
            continue

        diff = diff_cache.get(url, "")
        if not diff:
            dep_cache[url] = {}
            continue

        # Extract changed file paths from diff
        changed_files = []
        for line in diff.split("\n"):
            if line.startswith("+++ b/") or line.startswith("--- a/"):
                path = line.split("/", 1)[1] if "/" in line else line[6:]
                if path and path != "/dev/null":
                    ext = "." + path.rsplit(".", 1)[-1] if "." in path else ""
                    if ext in supported_exts:
                        full = repo_path / path
                        if full.exists():
                            changed_files.append(path)

        changed_files = list(set(changed_files))
        if not changed_files:
            dep_cache[url] = {}
            continue

        # Run sem graph on all changed files at once (cross-file deps!)
        try:
            result = subprocess.run(
                [str(SEM_BIN), "graph", "--format", "json"] + changed_files,
                capture_output=True, text=True, timeout=30,
                cwd=str(repo_path)
            )
            if result.returncode != 0:
                dep_cache[url] = {}
                continue

            graph_data = json.loads(result.stdout)
            edges = graph_data.get("graph", [])

            # Build per-entity dependency maps
            entity_deps = {}  # entity_name -> {dependents: set, dependencies: set}
            for edge in edges:
                from_name = edge["from"].split("::")[-1]
                to_name = edge["to"].split("::")[-1]
                from_file = edge["from"].split("::")[0]
                to_file = edge["to"].split("::")[0]

                entity_deps.setdefault(from_name, {"dependents": set(), "dependencies": set(), "file": from_file})
                entity_deps.setdefault(to_name, {"dependents": set(), "dependencies": set(), "file": to_file})

                entity_deps[from_name]["dependencies"].add(to_name)
                entity_deps[to_name]["dependents"].add(from_name)

            # Convert sets to lists for JSON serialization
            pr_deps = {}
            for name, info in entity_deps.items():
                pr_deps[name] = {
                    "dependents": sorted(info["dependents"]),
                    "dependencies": sorted(info["dependencies"]),
                    "dep_count": len(info["dependents"]),
                    "file": info["file"],
                }

            dep_cache[url] = pr_deps
            print(f"  {owner_repo}#{pr_number}: {len(changed_files)} files, {graph_data.get('entities', 0)} entities, {graph_data.get('edges', 0)} edges")

        except Exception as e:
            print(f"  {owner_repo}#{pr_number}: sem error: {e}")
            dep_cache[url] = {}

    with open(cache_path, "w") as f:
        json.dump(dep_cache, f, indent=2)

    print(f"Dependency cache built: {sum(len(v) for v in dep_cache.values())} total entities across {len(dep_cache)} PRs")
    return dep_cache


def build_wide_dep_cache(benchmark: dict, diff_cache: dict) -> dict:
    """Extended dep cache: sem graph within changed files + grep for cross-repo callers.
    Returns {pr_url: {entity_name: {dependents: [...], dep_count: N, repo_callers: N}}}."""
    import re as _re

    cache_path = OUTPUT_DIR / "wide_dep_cache.json"
    if cache_path.exists():
        with open(cache_path) as f:
            return json.load(f)

    # Start from narrow dep cache
    narrow = build_dep_cache(benchmark, diff_cache)

    wide_cache = {}
    supported_exts = {".java", ".py", ".go", ".ts", ".tsx", ".js", ".jsx", ".rs", ".rb"}
    ext_to_glob = {
        ".java": "*.java", ".py": "*.py", ".go": "*.go",
        ".ts": "*.ts", ".tsx": "*.tsx", ".js": "*.js", ".jsx": "*.jsx",
        ".rs": "*.rs", ".rb": "*.rb",
    }

    for url, entry in benchmark.items():
        parts = url.split("/")
        owner_repo = parts[3] + "/" + parts[4]
        pr_number = parts[6]
        repo_dir_name = REPO_DIR_MAP.get(owner_repo)
        if not repo_dir_name:
            wide_cache[url] = narrow.get(url, {})
            continue

        repo_path = REPOS_DIR / repo_dir_name
        if not repo_path.exists():
            wide_cache[url] = narrow.get(url, {})
            continue

        pr_deps = dict(narrow.get(url, {}))

        # Find high-value entity names to search for across the repo
        # Only search for method/class/function names (not fields, chunks)
        diff = diff_cache.get(url, "")
        changed_files = set()
        for line in diff.split("\n"):
            if line.startswith("+++ b/") or line.startswith("--- a/"):
                path = line.split("/", 1)[1] if "/" in line else line[6:]
                if path and path != "/dev/null":
                    changed_files.add(path)

        # Get top entities by dep_count from narrow cache
        entity_names = []
        for name, info in pr_deps.items():
            # Only grep for meaningful names (not generic like "get", "set", "new")
            if len(name) >= 4 and name not in ("self", "this", "None", "null", "true", "false"):
                entity_names.append(name)

        # Limit to top 10 most interesting names
        entity_names = sorted(entity_names, key=lambda n: pr_deps.get(n, {}).get("dep_count", 0), reverse=True)[:10]

        for name in entity_names:
            # Determine file extension to search
            entity_file = pr_deps.get(name, {}).get("file", "")
            ext = "." + entity_file.rsplit(".", 1)[-1] if "." in entity_file else ""
            include = ext_to_glob.get(ext, "")
            if not include:
                continue

            try:
                result = subprocess.run(
                    ["grep", "-rl", "--include=" + include, name, "."],
                    capture_output=True, text=True, timeout=10,
                    cwd=str(repo_path)
                )
                if result.returncode == 0:
                    caller_files = [f.strip().lstrip("./") for f in result.stdout.strip().split("\n") if f.strip()]
                    # Exclude the entity's own file
                    external_callers = [f for f in caller_files if f not in changed_files]
                    repo_caller_count = len(external_callers)

                    if name in pr_deps:
                        pr_deps[name]["repo_callers"] = repo_caller_count
                        pr_deps[name]["repo_caller_files"] = external_callers[:10]
                    else:
                        pr_deps[name] = {
                            "dependents": [],
                            "dependencies": [],
                            "dep_count": 0,
                            "file": entity_file,
                            "repo_callers": repo_caller_count,
                            "repo_caller_files": external_callers[:10],
                        }
            except Exception:
                pass

        wide_cache[url] = pr_deps
        enriched = sum(1 for v in pr_deps.values() if v.get("repo_callers", 0) > 0)
        print(f"  {owner_repo}#{pr_number}: {enriched} entities with repo-wide callers")

    with open(cache_path, "w") as f:
        json.dump(wide_cache, f, indent=2)

    total_with_callers = sum(1 for pr in wide_cache.values() for v in pr.values() if v.get("repo_callers", 0) > 0)
    print(f"Wide dep cache built: {total_with_callers} entities with repo-wide caller data")
    return wide_cache


def extract_caller_code_for_pr(pr_url: str, entities: list, dep_data: dict) -> dict:
    """Extract actual caller code snippets for top changed entities in a PR.
    Returns {entity_name: {'before': str, 'after': str, 'entity_type': str,
                           'file_path': str, 'callers': [{'file': str, 'code': str}]}}"""
    parts = pr_url.split("/")
    owner_repo = parts[3] + "/" + parts[4]
    repo_dir_name = REPO_DIR_MAP.get(owner_repo)
    if not repo_dir_name:
        return {}
    repo_path = REPOS_DIR / repo_dir_name
    if not repo_path.exists():
        return {}

    # Find modified entities with callers
    candidates = []
    for e in entities:
        name = e.get("entity_name", "")
        if not name or e.get("entity_type") in ("chunk",):
            continue
        if e.get("change_type") not in ("modified", "added"):
            continue
        # Skip very generic names that would match everywhere
        if len(name) < 4 or name in ("self", "this", "None", "null", "true", "false", "test", "main", "init", "new"):
            continue
        dep_info = dep_data.get(name, {})
        caller_files = dep_info.get("repo_caller_files", [])
        if caller_files:
            candidates.append((name, caller_files, len(caller_files), e))

    candidates.sort(key=lambda x: x[2], reverse=True)

    result = {}
    for name, caller_files, _, entity in candidates[:5]:
        before = (entity.get("before_content", "") or "")[:600]
        after = (entity.get("after_content", "") or "")[:600]

        callers = []
        for cf in caller_files[:3]:
            full_path = repo_path / cf
            if not full_path.exists():
                continue
            try:
                content = full_path.read_text(errors='replace')
                lines = content.split('\n')
                for i, line in enumerate(lines):
                    if name in line:
                        start = max(0, i - 8)
                        end = min(len(lines), i + 5)
                        snippet = '\n'.join(lines[start:end])
                        callers.append({'file': cf, 'code': snippet[:600]})
                        break
            except Exception:
                pass

        if callers:
            result[name] = {
                'before': before,
                'after': after,
                'entity_type': entity.get("entity_type", "?"),
                'file_path': entity.get("file_path", "?"),
                'callers': callers,
            }

    return result


def build_dep_enriched_triage(entities: list[dict], dep_data: dict) -> str:
    """Triage with dependency context from sem graph. Shows callers/callees for each entity."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)
                  and not (e.get("structural_change") == False)]
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
    top = meaningful[:20]

    if not top:
        return build_rich_triage_v29(entities)

    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    lines = ["## Entity-level triage with dependency context:"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        lines.append(f"\n**{fp}**:")
        for e in ents:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            public = " [PUBLIC API]" if e.get("is_public_api") else ""

            # Look up dependency info from sem graph
            dep_info = dep_data.get(name, {})
            dependents = dep_info.get("dependents", [])
            dep_count = dep_info.get("dep_count", 0)

            dep_str = ""
            if dep_count > 0:
                callers = ", ".join(dependents[:5])
                if dep_count > 5:
                    dep_str = f" [CALLED BY {dep_count}: {callers}, ...]"
                else:
                    dep_str = f" [CALLED BY: {callers}]"

            lines.append(f"  - {name} ({etype}, {change}, {classification}){public}{dep_str}")

    return "\n".join(lines)


def build_wide_dep_enriched_triage(entities: list[dict], dep_data: dict) -> str:
    """Triage with repo-wide dependency context. Shows local + repo-wide callers."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)
                  and not (e.get("structural_change") == False)]

    # Re-rank entities by combining risk_score with dependency impact
    for e in meaningful:
        name = e.get("entity_name", "?")
        dep_info = dep_data.get(name, {})
        repo_callers = dep_info.get("repo_callers", 0)
        local_deps = dep_info.get("dep_count", 0)
        # Boost risk score by dependency impact (log scale)
        import math
        dep_boost = math.log2(max(repo_callers + local_deps, 1) + 1) * 0.1
        e["_boosted_risk"] = e.get("risk_score", 0) + dep_boost

    meaningful.sort(key=lambda e: e.get("_boosted_risk", 0), reverse=True)
    top = meaningful[:20]

    if not top:
        return build_rich_triage_v29(entities)

    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    lines = ["## Entity-level triage with dependency context:"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("_boosted_risk", 0) for e in x[1]), reverse=True):
        lines.append(f"\n**{fp}**:")
        for e in ents:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            public = " [PUBLIC API]" if e.get("is_public_api") else ""

            dep_info = dep_data.get(name, {})
            local_deps = dep_info.get("dep_count", 0)
            repo_callers = dep_info.get("repo_callers", 0)

            dep_str = ""
            if repo_callers > 0:
                dep_str = f" [USED BY {repo_callers} files across repo]"
            elif local_deps > 0:
                callers = ", ".join(dep_info.get("dependents", [])[:3])
                dep_str = f" [called by: {callers}]"

            lines.append(f"  - {name} ({etype}, {change}, {classification}){public}{dep_str}")

    return "\n".join(lines)


def _get_change_summary(entity: dict) -> str:
    """Generate a one-line summary of what changed by diffing before/after content."""
    before = entity.get("before_content", "") or ""
    after = entity.get("after_content", "") or ""
    if not before and not after:
        return ""
    if not before:
        return "new entity"
    if not after:
        return "deleted"
    before_lines = before.strip().split("\n")
    after_lines = after.strip().split("\n")
    # Find first differing line
    for b, a in zip(before_lines, after_lines):
        if b.strip() != a.strip():
            b_s = b.strip()[:60]
            a_s = a.strip()[:60]
            return f"{b_s} -> {a_s}"
    if len(after_lines) > len(before_lines):
        added = [l.strip() for l in after_lines[len(before_lines):] if l.strip()]
        if added:
            return f"+{len(added)} lines: {added[0][:60]}"
    elif len(before_lines) > len(after_lines):
        return f"-{len(before_lines) - len(after_lines)} lines removed"
    return ""


def _risk_level(score: float) -> str:
    if score >= 0.7:
        return "CRITICAL"
    if score >= 0.4:
        return "HIGH"
    if score >= 0.2:
        return "MEDIUM"
    return "LOW"


def build_rich_triage_v38(entities: list[dict]) -> str:
    """Enriched triage ~6K chars. 30 entities, risk level word + change summary."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)
                  and not (e.get("structural_change") == False)]
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
    top = meaningful[:30]

    if not top:
        return build_triage_section(entities)

    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    lines = ["## Entity-level triage (highest-risk changes, ranked by impact):"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        lines.append(f"\n**{fp}**:")
        for e in ents:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            risk = e.get("risk_score", 0)
            blast = e.get("blast_radius", 0)
            dep_count = e.get("dependent_count", 0)
            deps_count = e.get("dependency_count", 0)
            public = " [PUBLIC API]" if e.get("is_public_api") else ""
            level = _risk_level(risk)

            parts = [f"{name} ({etype}, {change}, {classification}){public}"]
            parts.append(f"[{level}] risk={risk:.2f}")
            if blast > 0:
                parts.append(f"blast={blast}")
            if dep_count > 0:
                parts.append(f"callers={dep_count}")
            if deps_count > 0:
                parts.append(f"deps={deps_count}")

            summary = _get_change_summary(e)
            if summary:
                lines.append(f"  - {' '.join(parts)}")
                lines.append(f"    change: {summary}")
            else:
                lines.append(f"  - {' '.join(parts)}")

    return "\n".join(lines)


