def build_rich_triage_v32(entities: list[dict]) -> str:
    """Super-enriched triage with code snippets, line ranges, and dependency info. ~8K chars.
    Tells the LLM not just WHERE to look, but WHAT changed."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)
                  and not (e.get("structural_change") == False)]
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
    top = meaningful[:25]  # fewer entities but richer info per entity

    if not top:
        return build_triage_section(entities)

    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    lines = ["## Entity-level triage (highest-risk changes with code context):"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        lines.append(f"\n**{fp}**:")
        for e in ents:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            risk = e.get("risk_score", 0)
            risk_lvl = e.get("risk_level", "")
            blast = e.get("blast_radius", 0)
            dep_count = e.get("dependent_count", 0)
            deps_count = e.get("dependency_count", 0)
            public = " [PUBLIC API]" if e.get("is_public_api") else ""
            start = e.get("start_line", 0)
            end = e.get("end_line", 0)

            # Header line with all metadata
            meta = [f"risk={risk:.2f} ({risk_lvl})"]
            if blast > 0:
                meta.append(f"blast={blast}")
            if dep_count > 0:
                meta.append(f"callers={dep_count}")
            if deps_count > 0:
                meta.append(f"deps={deps_count}")
            if start > 0:
                meta.append(f"L{start}-{end}")
            lines.append(f"  - {name} ({etype}, {change}, {classification}){public} {' '.join(meta)}")

            # Code snippet: show first 200 chars of after_content (the current code)
            after = e.get("after_content", "")
            before = e.get("before_content", "")
            if after and change == "modified" and before:
                # Show a brief diff hint: first line that differs
                after_lines = after.split("\n")
                before_lines = before.split("\n")
                diff_hint = ""
                for al, bl in zip(after_lines, before_lines):
                    if al.strip() != bl.strip():
                        diff_hint = f"    changed: `{bl.strip()[:80]}` -> `{al.strip()[:80]}`"
                        break
                if not diff_hint and len(after_lines) != len(before_lines):
                    diff_hint = f"    {len(after_lines) - len(before_lines):+d} lines"
                if diff_hint:
                    lines.append(diff_hint)
            elif after and change == "added":
                snippet = after.strip().split("\n")[0][:100]
                lines.append(f"    new: `{snippet}`")

    return "\n".join(lines)


def load_or_build_diff_cache(benchmark: dict) -> dict:
    """Cache all PR diffs to avoid re-fetching on each run."""
    cache = {}
    if DIFF_CACHE.exists():
        with open(DIFF_CACHE) as f:
            cache = json.load(f)

    missing = [url for url in benchmark if url not in cache]
    if missing:
        print(f"Fetching {len(missing)} PR diffs...")
        for i, url in enumerate(missing):
            info = extract_pr_info(url)
            if not info:
                cache[url] = ""
                continue
            owner_repo, pr_number = info
            print(f"  [{i+1}/{len(missing)}] {owner_repo}#{pr_number}...", end=" ", flush=True)
            diff = fetch_pr_diff(owner_repo, pr_number)
            cache[url] = diff or ""
            print("ok" if diff else "fail")

        with open(DIFF_CACHE, "w") as f:
            json.dump(cache, f)
        print(f"Cached {len(cache)} diffs.")

    return cache


async def review_precise(pr_title: str, diff: str, triage_section: str, client) -> list[str]:
    """Strategy: precise - single pass, strict prompt, max 5 issues."""
    truncated = truncate_diff(diff)
    prompt = PROMPT_PRECISE.format(pr_title=pr_title, triage_section=triage_section, diff=truncated)
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise code reviewer. Only report real bugs. Always respond with valid JSON."},
                    {"role": "user", "content": prompt},
                ],
                temperature=0.0,
            ),
            timeout=90,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        data = json.loads(content)
        issues = data.get("issues", [])
        return issues[:5]  # Hard cap
    except Exception as e:
        print(f"  LLM failed: {e}")
        return []


