async def review_entity_focused(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: entity_focused - include actual entity code changes."""
    truncated = truncate_diff(diff, max_chars=16000)
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")

    # Build entity changes section from inspect data
    entity_section = ""
    if entities:
        modified_or_added = [e for e in entities if e.get("change_type") in ("modified", "added") and (e.get("before_content") or e.get("after_content"))]
        modified_or_added.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
        top = modified_or_added[:10]

        parts = []
        for e in top:
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            fpath = e.get("file_path", "?")
            change = e.get("change_type", "?")
            risk = e.get("risk_score", 0)
            classification = e.get("classification", "?")

            part = f"### {fpath}::{name} ({etype}, {change}, risk={risk:.2f}, {classification})"
            before = (e.get("before_content") or "")[:400]
            after = (e.get("after_content") or "")[:400]
            if before and after and before != after:
                part += f"\nBefore:\n```\n{before}\n```\nAfter:\n```\n{after}\n```"
            elif after:
                part += f"\nAdded:\n```\n{after}\n```"

            deps = e.get("dependent_names", [])
            if deps:
                part += f"\nUsed by: {', '.join(deps[:5])}"

            parts.append(part)

        entity_section = "\n\n".join(parts)

    if not entity_section:
        entity_section = triage_section or "(no entity data available)"

    prompt = PROMPT_ENTITY_FOCUSED.format(pr_title=pr_title, entity_changes=entity_section, diff=truncated)

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."},
                    {"role": "user", "content": prompt},
                ],
                temperature=0.0,
            ),
            timeout=90,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        data = json.loads(content)
        return data.get("issues", [])[:7]
    except Exception as e:
        print(f"  LLM failed: {e}")
        return []


async def review_targeted_validated(pr_title: str, diff: str, triage_section: str, client) -> list[str]:
    """Strategy: targeted + validation pass. Best of both worlds."""
    truncated = truncate_diff(diff, max_chars=24000)
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")

    # Pass 1: targeted review
    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."},
                    {"role": "user", "content": PROMPT_TARGETED.format(pr_title=pr_title, triage_section=triage_section, diff=truncated)},
                ],
                temperature=0.0,
            ),
            timeout=90,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        raw_issues = json.loads(content).get("issues", [])
    except Exception as e:
        print(f"  Pass 1 failed: {e}")
        return []

    if len(raw_issues) <= 2:
        return raw_issues  # Few enough, keep all

    # Pass 2: validate - only if we have many candidates
    try:
        validate_prompt = f"""You are a senior code reviewer doing final validation.

PR Title: {pr_title}

Below are candidate issues found in a code review. For each one, decide: is this a REAL concrete bug that would cause incorrect behavior, or is it speculative/theoretical?

Candidates:
{json.dumps(raw_issues, indent=2)}

Keep ONLY issues that describe a concrete, specific bug. Remove anything that is:
- Speculative ("could potentially cause...")
- About missing features or improvements
- About code style or naming
- About removed/deleted code that's being replaced

Respond with ONLY a JSON object:
{{"issues": ["validated issue 1", ...]}}"""

        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Only keep real bugs. Always respond with valid JSON."},
                    {"role": "user", "content": validate_prompt},
                ],
                temperature=0.0,
            ),
            timeout=60,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"  Pass 2 failed: {e}")
        return raw_issues[:5]


PROMPT_DEEP = """You are a world-class code reviewer. Review this PR and find ONLY real, concrete bugs.

PR Title: {pr_title}

{triage_section}

PR Diff:
{diff}

Look specifically for these categories of issues:
1. Logic errors: wrong conditions, off-by-one, incorrect algorithms, broken control flow, inverted booleans
2. Concurrency bugs: race conditions, missing locks, unsafe shared state, deadlocks, unhandled async promises
3. Null/undefined safety: missing null checks, possible NPE, Optional.get() without isPresent(), uninitialized variables
4. Error handling: swallowed exceptions, missing error propagation, wrong error types
5. Data correctness: wrong translations, wrong constants, incorrect mappings, copy-paste errors, stale cache data
6. Security: SSRF, XSS, injection, auth bypass, exposed secrets, unsafe deserialization, origin validation bypass
7. Type mismatches: wrong return types, incompatible casts, API contract violations, schema errors
8. Breaking changes: removed public APIs without migration, changed behavior silently
9. State consistency: asymmetric cache trust, orphaned data, inconsistent updates across related fields
10. Naming/contract bugs: method name typos that break interfaces, property names that don't match expected contracts

Rules:
- ONLY report issues you are highly confident about (>90% sure)
- Be specific: name the file, function/variable, and exactly what's wrong
- Naming typos ARE bugs if they would cause a runtime error or break an API contract
- Do NOT report: style preferences, missing tests, docs, "could be improved"
- Do NOT report issues about code that was only deleted/removed
- Maximum 10 issues. Quality over quantity.

For each issue, provide it as a JSON object with "issue" (description) and "evidence" (quote the specific code lines from the diff that prove this is a bug).

Respond with ONLY a JSON object:
{{"issues": [{{"issue": "description", "evidence": "the specific code"}}]}}"""


async def review_deep(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: deep_review - bigger context, enriched triage, diff-aware self-refine validation."""
    truncated = truncate_diff(diff, max_chars=40000)
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")

    # Build enriched triage from entity data
    rich_triage = build_rich_triage(entities) if entities else triage_section

    # Pass 1: targeted review with evidence requirement and bigger context
    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."},
                    {"role": "user", "content": PROMPT_DEEP.format(pr_title=pr_title, triage_section=rich_triage, diff=truncated)},
                ],
                temperature=0.0,
            ),
            timeout=120,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        raw_data = json.loads(content)
        raw_issues = raw_data.get("issues", [])
    except Exception as e:
        print(f"  Pass 1 failed: {e}")
        return []

    if not raw_issues:
        return []

    # Normalize: handle both string issues and {issue, evidence} objects
    structured = []
    for item in raw_issues:
        if isinstance(item, str):
            structured.append({"issue": item, "evidence": ""})
        elif isinstance(item, dict):
            structured.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})

    if len(structured) <= 2:
        return [s["issue"] for s in structured]

    # Pass 2: diff-aware self-refine validation
    # Key improvement: validation sees BOTH the diff AND the candidates
    try:
        candidates_text = "\n".join(
            f"{i+1}. {s['issue']}\n   Evidence: {s['evidence']}" if s['evidence']
            else f"{i+1}. {s['issue']}"
            for i, s in enumerate(structured)
        )

        refine_prompt = f"""You are a senior code reviewer doing final validation. You have the PR diff and candidate issues.

PR Title: {pr_title}

PR Diff (for verification):
{truncated}

Candidate Issues:
{candidates_text}

For each candidate, verify against the actual diff:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.

Return ONLY the issues that are verified real bugs with evidence in the diff.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the actual diff. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
            ),
            timeout=120,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"  Pass 2 failed: {e}")
        return [s["issue"] for s in structured[:5]]


async def review_deep_v2(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: deep_v2 - 80K context, two-temperature merge, diff-aware validation.
    Combines wider net (T=0 + T=0.3) with strict diff-aware filtering."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    rich_triage = build_rich_triage(entities) if entities else triage_section

    # 80K char window - GPT-5.2 handles 128K+ tokens
    truncated = truncate_diff(diff, max_chars=80000)

    async def review_pass(temp: float) -> list[dict]:
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."},
                        {"role": "user", "content": PROMPT_DEEP.format(pr_title=pr_title, triage_section=rich_triage, diff=truncated)},
                    ],
                    temperature=temp,
                ),
                timeout=180,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            items = json.loads(content).get("issues", [])
            result = []
            for item in items:
                if isinstance(item, str):
                    result.append({"issue": item, "evidence": ""})
                elif isinstance(item, dict):
                    result.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})
            return result
        except Exception as e:
            print(f"  pass(T={temp}) failed: {e}", end="", flush=True)
            return []

    # Two passes in parallel: deterministic + diverse
    n_passes = int(os.environ.get("DEEP_V2_PASSES", "2"))
    if n_passes == 3:
        pass_results = await asyncio.gather(review_pass(0.0), review_pass(0.3), review_pass(0.5))
        pass_0, pass_1 = pass_results[0], pass_results[1] + pass_results[2]
    else:
        pass_0, pass_1 = await asyncio.gather(review_pass(0.0), review_pass(0.3))

    # Merge: take all from T=0, add unique from T=0.3
    all_issues = list(pass_0)
    existing_lower = {s["issue"].lower()[:80] for s in all_issues}
    for s in pass_1:
        key = s["issue"].lower()[:80]
        if key not in existing_lower:
            all_issues.append(s)
            existing_lower.add(key)

    if not all_issues:
        return []

    if len(all_issues) <= 2:
        return [s["issue"] for s in all_issues]

    # Diff-aware validation
    try:
        candidates_text = "\n".join(
            f"{i+1}. {s['issue']}" + (f"\n   Evidence: {s['evidence']}" if s['evidence'] else "")
            for i, s in enumerate(all_issues)
        )

        refine_prompt = f"""You are a senior code reviewer doing final validation. You have the PR diff and candidate issues.

PR Title: {pr_title}

PR Diff (for verification):
{truncated}

Candidate Issues:
{candidates_text}

For each candidate, verify against the actual diff:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.

Return ONLY the issues that are verified real bugs with evidence in the diff.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the actual diff. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
            ),
            timeout=180,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"  validation failed: {e}")
        return [s["issue"] for s in all_issues[:5]]


