def shuffle_diff_files(diff: str) -> str:
    """Shuffle the order of files in a diff. Cursor's key insight: different file
    orderings cause the LLM to focus on different parts of the code."""
    parts = diff.split("diff --git ")
    if len(parts) <= 2:
        return diff
    header = parts[0]
    files = [f for f in parts[1:] if f.strip()]
    random.shuffle(files)
    return header + "diff --git " + "diff --git ".join(files)


async def review_consensus(pr_title: str, diff: str, triage_section: str, client) -> list[str]:
    """Strategy: consensus - 3 parallel runs with shuffled diff order + LLM aggregation.
    Based on Cursor Bugbot's approach (8 passes + voting) and SWR-Bench research (+43% F1)."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    n_runs = 3

    async def single_run(run_idx: int) -> list[str]:
        # Shuffle diff order for diversity (Cursor's technique)
        shuffled = shuffle_diff_files(diff) if run_idx > 0 else diff
        truncated = truncate_diff(shuffled, max_chars=24000)
        prompt = PROMPT_TARGETED.format(pr_title=pr_title, triage_section=triage_section, diff=truncated)
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=0.5 if run_idx > 0 else 0.0,  # First run deterministic, others diverse
                ),
                timeout=90,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            return json.loads(content).get("issues", [])[:7]
        except Exception as e:
            print(f"  run{run_idx} failed: {e}", end="", flush=True)
            return []

    # Run all 3 in parallel
    all_runs = await asyncio.gather(*[single_run(i) for i in range(n_runs)])
    all_issues = []
    for run_issues in all_runs:
        all_issues.extend(run_issues)

    if not all_issues:
        return []

    if len(all_issues) <= 3:
        return list(set(all_issues))  # Deduplicate trivially

    # Universal Self-Consistency aggregation: LLM picks findings that appear consistently
    try:
        runs_text = ""
        for i, run_issues in enumerate(all_runs):
            runs_text += f"\nRun {i+1} findings:\n{json.dumps(run_issues, indent=2)}\n"

        agg_prompt = f"""You are aggregating code review results from 3 independent review passes of the same PR.

PR Title: {pr_title}

{runs_text}

Instructions:
1. Identify issues that appear in 2 or more runs (same underlying bug, even if worded differently).
2. ONLY include issues found in 2+ runs. Single-run findings are likely false positives and should be dropped.
3. For each kept issue, use the clearest description from any run.
4. Remove anything speculative, style-related, or about deleted code.

Respond with ONLY a JSON object:
{{"issues": ["validated issue 1", ...]}}"""

        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer aggregating multiple review passes. Keep findings that appear consistently. Always respond with valid JSON."},
                    {"role": "user", "content": agg_prompt},
                ],
                temperature=0.0,
            ),
            timeout=60,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"  aggregation failed: {e}", end="", flush=True)
        # Fallback: just deduplicate by taking first run
        return all_runs[0][:5] if all_runs[0] else all_issues[:5]


