async def review_deep_v14(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: deep_v14 - v11 but ALWAYS validate (remove <=3 bypass).
    v11 skips validation for PRs with <=3 raw candidates. This lets FPs through
    on low-output PRs. v14 validates everything. The goal: cut ~5-10 FPs from
    low-output PRs while keeping TPs. Should improve precision without hurting recall."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)
