async def review_deep_v100(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None, dep_data: dict = None) -> list[str]:
    """Strategy: deep_v100 - Dep-ranked triage + dep-enriched validation only.
    Key insight: dep data in generation increases FPs. Better to:
    1. Use dep data to RANK entities in triage (high-impact first)
    2. Use v29 prompts for generation (no dep text, proven best)
    3. Use dep data in VALIDATION to help keep/drop decisions
    All T=0, seed=42. Deterministic."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)

    # Build dep-ranked triage but WITHOUT showing dep counts/callers to the LLM
    if dep_data and entities:
        import math
        meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                      and e.get("entity_type") not in ("chunk",)
                      and not (e.get("structural_change") == False)]
        for e in meaningful:
            name = e.get("entity_name", "?")
            dep_info = dep_data.get(name, {})
            repo_callers = dep_info.get("repo_callers", 0)
            local_deps = dep_info.get("dep_count", 0)
            dep_boost = math.log2(max(repo_callers + local_deps, 1) + 1) * 0.1
            e["_boosted_risk"] = e.get("risk_score", 0) + dep_boost

        meaningful.sort(key=lambda e: e.get("_boosted_risk", 0), reverse=True)
        top = meaningful[:20]
        by_file = {}
        for e in top:
            fp = e.get("file_path", "")
            by_file.setdefault(fp, []).append(e)

        triage_lines = ["## Entity-level triage (highest-risk changes):"]
        for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("_boosted_risk", 0) for e in x[1]), reverse=True):
            triage_lines.append(f"\n**{fp}**:")
            for e in ents:
                name = e.get("entity_name", "?")
                etype = e.get("entity_type", "?")
                change = e.get("change_type", "?")
                classification = e.get("classification", "?")
                public = " [PUBLIC API]" if e.get("is_public_api") else ""
                triage_lines.append(f"  - {name} ({etype}, {change}, {classification}){public}")
        rich_triage = "\n".join(triage_lines)
    elif entities:
        rich_triage = build_rich_triage_v29(entities)
    else:
        rich_triage = triage_section

    # Extract diff file paths for structural filter
    diff_files = set()
    for line in diff.split("\n"):
        if line.startswith("+++ b/") or line.startswith("--- a/"):
            path = line.split("/", 1)[1] if "/" in line else line[6:]
            if path and path != "/dev/null":
                diff_files.add(path)
                diff_files.add(path.rsplit("/", 1)[-1])

    async def run_lens(system_msg: str, prompt: str, temp: float, seed: int = 42) -> list[dict]:
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": system_msg},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=temp,
                    seed=seed,
                ),
                timeout=180,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            items = json.loads(content).get("issues", [])
            result = []
            for item in items:
                if isinstance(item, str):
                    result.append({"issue": item, "evidence": ""})
                elif isinstance(item, dict):
                    result.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})
            return result
        except Exception as e:
            print(f"[lens-err:{e}]", end="", flush=True)
            return []

    # EXACT v29 prompts (no dep data injected) - proven best for generation
    prompt_data = f"""You are a code reviewer specializing in DATA CORRECTNESS issues.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: wrong translations, wrong constants/mappings/enum values, copy-paste errors, wrong key/field references, case sensitivity in comparisons, incorrect regex.
Rules: ONLY concrete data issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_concurrency = f"""You are a code reviewer specializing in CONCURRENCY and STATE bugs.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: race conditions, missing locks/transactions, stale reads, process lifecycle bugs, cache inconsistency, feature flag inconsistency.
Rules: ONLY issues with evidence in the diff. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_contracts = f"""You are a code reviewer specializing in API CONTRACT violations.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: missing abstract method implementations, wrong signatures/types, API breaking changes, wrong parameter order, key mismatches, missing React keys, import errors, method name typos breaking interfaces.
Rules: ONLY verifiable issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_security = f"""You are a security-focused code reviewer.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: SSRF, XSS, injection, auth bypass, origin/referrer bypass, case sensitivity bypass in security comparisons, frame options misconfig, hardcoded secrets.
Rules: ONLY real exploitable vulnerabilities. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_typos = f"""You are a code reviewer with exceptional attention to character-level detail.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on:
- Method/function/variable name TYPOS causing runtime errors
- Wrong language in locale/translation files
- Missing required method suffixes (Rails '?', etc.)
- Case sensitivity bugs in comparisons
- Wrong vendor prefixes
- Property/key name mismatches

Rules: Character-level precision. Only if it causes runtime failure. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_runtime = f"""You are a code reviewer focused on RUNTIME FAILURES.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

For each changed function/class, ask: "What would happen if I ran this code?"

Focus ONLY on:
- Null/nil/undefined dereference
- Missing abstract method implementations causing TypeError
- Unreachable code branches
- Infinite recursion without termination
- Wrong error messages
- Panic on nil in Go
- Missing React keys

Rules: RUNTIME behavior only. Only actual failures. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_general = PROMPT_DEEP.format(pr_title=pr_title, triage_section=rich_triage, diff=truncated)
    sys_precise = "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."

    results = await asyncio.gather(
        run_lens("You are a data correctness reviewer. Always respond with valid JSON.", prompt_data, 0.0),
        run_lens("You are a concurrency/state bug reviewer. Always respond with valid JSON.", prompt_concurrency, 0.0),
        run_lens("You are an API contracts reviewer. Always respond with valid JSON.", prompt_contracts, 0.0),
        run_lens("You are a security reviewer. Always respond with valid JSON.", prompt_security, 0.0),
        run_lens("You are a character-level detail reviewer. Always respond with valid JSON.", prompt_typos, 0.0),
        run_lens("You are a runtime failure analyst. Always respond with valid JSON.", prompt_runtime, 0.0),
        run_lens(sys_precise, prompt_general, 0.0),
        run_lens(sys_precise, prompt_general, 0.15, seed=42),
        run_lens(sys_precise, prompt_general, 0.15, seed=123),
    )

    # Merge + dedup
    all_issues = []
    existing_lower = set()
    for pass_result in results:
        for s in pass_result:
            key = s["issue"].lower()[:80]
            if key not in existing_lower:
                all_issues.append(s)
                existing_lower.add(key)

    if not all_issues:
        return []

    # Structural file filter
    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl"}
        filtered = []
        dropped = 0
        for s in all_issues:
            text = s["issue"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in {f.lower().rsplit("/", 1)[-1] for f in diff_files}:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(s)
        if dropped:
            print(f"[-{dropped}file]", end="", flush=True)
        all_issues = filtered

    if not all_issues:
        return []

    print(f"[{len(all_issues)} raw]", end="", flush=True)

    # Build entity verification context
    entity_verify_ctx = ""
    if entities:
        candidate_texts = [s["issue"] for s in all_issues]
        entity_verify_ctx = build_entity_verification_context(entities, candidate_texts)

    entity_section = ""
    if entity_verify_ctx:
        entity_section = f"""

## Entity Code (before/after, for verification):
{entity_verify_ctx}
"""

    # DEP-ENRICHED VALIDATION: Add blast radius to help validator make better decisions
    dep_val_section = ""
    if dep_data:
        dep_lines = []
        for name, info in sorted(dep_data.items(), key=lambda x: x[1].get("repo_callers", 0) + x[1].get("dep_count", 0), reverse=True):
            repo_callers = info.get("repo_callers", 0)
            local_deps = info.get("dep_count", 0)
            if repo_callers > 0 or local_deps >= 3:
                dep_lines.append(f"  {name}: {repo_callers} repo-wide callers, {local_deps} local callers")
        if dep_lines:
            dep_val_section = f"""

## Dependency graph (blast radius of each entity):
{chr(10).join(dep_lines[:25])}

Use this context: bugs in entities with many callers are more impactful and more likely to be real.
"""

    candidates_text = "\n".join(
        f"{i+1}. {s['issue']}" + (f"\n   Evidence: {s['evidence']}" if s['evidence'] else "")
        for i, s in enumerate(all_issues)
    )

    refine_prompt = f"""You are a senior code reviewer doing final validation. You have the PR diff, entity code, dependency context, and candidate issues.

PR Title: {pr_title}

PR Diff (for verification):
{truncated}
{entity_section}{dep_val_section}
Candidate Issues:
{candidates_text}

For each candidate, verify against the actual diff and entity code:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.

Return ONLY the issues that are verified real bugs with evidence in the diff.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the actual diff and entity code. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=180,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"[val-err:{e.__class__.__name__}]", end="", flush=True)
        return [s["issue"] for s in all_issues[:5]]


async def review_deep_v110(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None, dep_data: dict = None) -> list[str]:
    """Strategy: deep_v110 - Multi-lens consensus + dep-ranked triage + dep validation.
    Key insight: issues found by multiple lenses are more likely real.
    1. Run 9 lenses (v29 prompts, dep-ranked triage, no dep text in prompts)
    2. Score each issue by how many lenses found something similar
    3. Sort by consensus score, then validate top-scoring first
    4. Dep-enriched validation for better keep/drop
    5. Cap at 7
    All T=0, seed=42."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)

    # Dep-ranked triage without dep text (same as v100)
    if dep_data and entities:
        import math
        meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                      and e.get("entity_type") not in ("chunk",)
                      and not (e.get("structural_change") == False)]
        for e in meaningful:
            name = e.get("entity_name", "?")
            dep_info = dep_data.get(name, {})
            repo_callers = dep_info.get("repo_callers", 0)
            local_deps = dep_info.get("dep_count", 0)
            dep_boost = math.log2(max(repo_callers + local_deps, 1) + 1) * 0.1
            e["_boosted_risk"] = e.get("risk_score", 0) + dep_boost

        meaningful.sort(key=lambda e: e.get("_boosted_risk", 0), reverse=True)
        top = meaningful[:20]
        by_file = {}
        for e in top:
            fp = e.get("file_path", "")
            by_file.setdefault(fp, []).append(e)

        triage_lines = ["## Entity-level triage (highest-risk changes):"]
        for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("_boosted_risk", 0) for e in x[1]), reverse=True):
            triage_lines.append(f"\n**{fp}**:")
            for e in ents:
                name = e.get("entity_name", "?")
                etype = e.get("entity_type", "?")
                change = e.get("change_type", "?")
                classification = e.get("classification", "?")
                public = " [PUBLIC API]" if e.get("is_public_api") else ""
                triage_lines.append(f"  - {name} ({etype}, {change}, {classification}){public}")
        rich_triage = "\n".join(triage_lines)
    elif entities:
        rich_triage = build_rich_triage_v29(entities)
    else:
        rich_triage = triage_section

    # Extract diff file paths for structural filter
    diff_files = set()
    for line in diff.split("\n"):
        if line.startswith("+++ b/") or line.startswith("--- a/"):
            path = line.split("/", 1)[1] if "/" in line else line[6:]
            if path and path != "/dev/null":
                diff_files.add(path)
                diff_files.add(path.rsplit("/", 1)[-1])

    async def run_lens(system_msg: str, prompt: str, temp: float, seed: int = 42) -> list[dict]:
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": system_msg},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=temp,
                    seed=seed,
                ),
                timeout=180,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            items = json.loads(content).get("issues", [])
            result = []
            for item in items:
                if isinstance(item, str):
                    result.append({"issue": item, "evidence": ""})
                elif isinstance(item, dict):
                    result.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})
            return result
        except Exception as e:
            print(f"[lens-err:{e}]", end="", flush=True)
            return []

    # EXACT v29 prompts (no dep text)
    prompt_data = f"""You are a code reviewer specializing in DATA CORRECTNESS issues.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: wrong translations, wrong constants/mappings/enum values, copy-paste errors, wrong key/field references, case sensitivity in comparisons, incorrect regex.
Rules: ONLY concrete data issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_concurrency = f"""You are a code reviewer specializing in CONCURRENCY and STATE bugs.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: race conditions, missing locks/transactions, stale reads, process lifecycle bugs, cache inconsistency, feature flag inconsistency.
Rules: ONLY issues with evidence in the diff. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_contracts = f"""You are a code reviewer specializing in API CONTRACT violations.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: missing abstract method implementations, wrong signatures/types, API breaking changes, wrong parameter order, key mismatches, missing React keys, import errors, method name typos breaking interfaces.
Rules: ONLY verifiable issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_security = f"""You are a security-focused code reviewer.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: SSRF, XSS, injection, auth bypass, origin/referrer bypass, case sensitivity bypass in security comparisons, frame options misconfig, hardcoded secrets.
Rules: ONLY real exploitable vulnerabilities. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_typos = f"""You are a code reviewer with exceptional attention to character-level detail.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on:
- Method/function/variable name TYPOS causing runtime errors
- Wrong language in locale/translation files
- Missing required method suffixes (Rails '?', etc.)
- Case sensitivity bugs in comparisons
- Wrong vendor prefixes
- Property/key name mismatches

Rules: Character-level precision. Only if it causes runtime failure. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_runtime = f"""You are a code reviewer focused on RUNTIME FAILURES.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

For each changed function/class, ask: "What would happen if I ran this code?"

Focus ONLY on:
- Null/nil/undefined dereference
- Missing abstract method implementations causing TypeError
- Unreachable code branches
- Infinite recursion without termination
- Wrong error messages
- Panic on nil in Go
- Missing React keys

Rules: RUNTIME behavior only. Only actual failures. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_general = PROMPT_DEEP.format(pr_title=pr_title, triage_section=rich_triage, diff=truncated)
    sys_precise = "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."

    results = await asyncio.gather(
        run_lens("You are a data correctness reviewer. Always respond with valid JSON.", prompt_data, 0.0),
        run_lens("You are a concurrency/state bug reviewer. Always respond with valid JSON.", prompt_concurrency, 0.0),
        run_lens("You are an API contracts reviewer. Always respond with valid JSON.", prompt_contracts, 0.0),
        run_lens("You are a security reviewer. Always respond with valid JSON.", prompt_security, 0.0),
        run_lens("You are a character-level detail reviewer. Always respond with valid JSON.", prompt_typos, 0.0),
        run_lens("You are a runtime failure analyst. Always respond with valid JSON.", prompt_runtime, 0.0),
        run_lens(sys_precise, prompt_general, 0.0),
        run_lens(sys_precise, prompt_general, 0.15, seed=42),
        run_lens(sys_precise, prompt_general, 0.15, seed=123),
    )

    # CONSENSUS SCORING: track which issues are found by multiple lenses
    # For each issue, compute how many lenses found something similar (30-char prefix match)
    all_raw = []
    for lens_idx, pass_result in enumerate(results):
        for item in pass_result:
            all_raw.append({**item, "lens_idx": lens_idx})

    # Score by consensus: how many lenses found a similar issue?
    def similarity_key(text: str) -> str:
        return text.lower().strip()[:40]

    # Group by similarity
    from collections import Counter
    sim_keys = Counter()
    key_to_items = {}
    for item in all_raw:
        key = similarity_key(item["issue"])
        sim_keys[key] += 1
        if key not in key_to_items:
            key_to_items[key] = item

    # Dedup and assign consensus scores
    scored_issues = []
    seen_keys = set()
    for item in all_raw:
        key = similarity_key(item["issue"])
        full_key = item["issue"].lower()[:80]
        if full_key not in seen_keys:
            scored_issues.append({
                "issue": item["issue"],
                "evidence": item.get("evidence", ""),
                "consensus": sim_keys[key],
            })
            seen_keys.add(full_key)

    # Sort by consensus score (high first), then by original order
    scored_issues.sort(key=lambda x: x["consensus"], reverse=True)
    all_issues = scored_issues

    if not all_issues:
        return []

    # Structural file filter
    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl"}
        filtered = []
        dropped = 0
        for s in all_issues:
            text = s["issue"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in {f.lower().rsplit("/", 1)[-1] for f in diff_files}:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(s)
        if dropped:
            print(f"[-{dropped}file]", end="", flush=True)
        all_issues = filtered

    if not all_issues:
        return []

    # Log consensus distribution
    multi = sum(1 for s in all_issues if s["consensus"] > 1)
    print(f"[{len(all_issues)} raw, {multi} multi-lens]", end="", flush=True)

    # Build entity verification context
    entity_verify_ctx = ""
    if entities:
        candidate_texts = [s["issue"] for s in all_issues]
        entity_verify_ctx = build_entity_verification_context(entities, candidate_texts)

    entity_section = ""
    if entity_verify_ctx:
        entity_section = f"""

## Entity Code (before/after, for verification):
{entity_verify_ctx}
"""

    # Dep-enriched validation
    dep_val_section = ""
    if dep_data:
        dep_lines = []
        for name, info in sorted(dep_data.items(), key=lambda x: x[1].get("repo_callers", 0) + x[1].get("dep_count", 0), reverse=True):
            repo_callers = info.get("repo_callers", 0)
            local_deps = info.get("dep_count", 0)
            if repo_callers > 0 or local_deps >= 3:
                dep_lines.append(f"  {name}: {repo_callers} repo-wide callers, {local_deps} local callers")
        if dep_lines:
            dep_val_section = f"""

## Dependency graph (blast radius of each entity):
{chr(10).join(dep_lines[:25])}
"""

    # Include consensus scores in validation prompt
    candidates_text = "\n".join(
        f"{i+1}. [found by {s['consensus']} lens{'es' if s['consensus'] > 1 else ''}] {s['issue']}"
        + (f"\n   Evidence: {s['evidence']}" if s['evidence'] else "")
        for i, s in enumerate(all_issues)
    )

    refine_prompt = f"""You are a senior code reviewer doing final validation. You have the PR diff, entity code, dependency context, and candidate issues.

Each candidate shows how many independent review lenses flagged it. Issues found by multiple lenses are more likely real.

PR Title: {pr_title}

PR Diff (for verification):
{truncated}
{entity_section}{dep_val_section}
Candidate Issues (sorted by consensus):
{candidates_text}

For each candidate, verify against the actual diff and entity code:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.
6. Issues found by multiple lenses get benefit of the doubt. Issues found by only 1 lens need stronger evidence.

Return ONLY the issues that are verified real bugs with evidence in the diff.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the actual diff and entity code. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=180,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"[val-err:{e.__class__.__name__}]", end="", flush=True)
        return [s["issue"] for s in all_issues[:5]]


