def build_entity_review_context(entities: list[dict], max_chars: int = 120000) -> str:
    """Build the complete entity-only review context. No diff. Pure entity before/after code.
    Sorted by risk score. Includes change type, classification, dependency info."""
    if not entities:
        return ""

    # Filter to reviewable entities (skip chunks, properties, headings)
    reviewable = [
        e for e in entities
        if e.get("entity_type") not in ("chunk", "property", "heading", "section")
        and (e.get("before_content") or e.get("after_content"))
    ]
    if not reviewable:
        return ""

    reviewable.sort(key=lambda e: e.get("risk_score", 0), reverse=True)

    sections = []
    total = 0

    for e in reviewable:
        name = e.get("entity_name", "?")
        etype = e.get("entity_type", "?")
        fpath = e.get("file_path", "?")
        change = e.get("change_type", "?")
        classification = e.get("classification", "?")
        risk = e.get("risk_score", 0)
        public = " [PUBLIC API]" if e.get("is_public_api") else ""

        deps = e.get("dependent_names", [])
        if deps:
            dep_names = [d[0] if isinstance(d, (list, tuple)) else d.get("name", "") for d in deps[:5]]
            used_by = f"Used by: {', '.join(n for n in dep_names if n)}"
        else:
            used_by = ""

        section = f"\n### {fpath}::{name} ({etype}, {change}, {classification}, risk={risk:.2f}){public}"
        if used_by:
            section += f"\n{used_by}"

        before = e.get("before_content") or ""
        after = e.get("after_content") or ""

        if change in ("modified", "Modified") and before and after:
            section += f"\nBEFORE:\n```\n{before[:2000]}\n```\nAFTER:\n```\n{after[:2000]}\n```"
        elif change in ("added", "Added") and after:
            section += f"\nNEW:\n```\n{after[:2500]}\n```"
        elif change in ("deleted", "Deleted") and before:
            section += f"\nDELETED:\n```\n{before[:2500]}\n```"

        total += len(section)
        if total > max_chars:
            break
        sections.append(section)

    if not sections:
        return ""

    header = f"## Entity Changes ({len(sections)} entities, sorted by risk):"
    return header + "\n".join(sections)


