async def review_deep_v13(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: deep_v13 - v11 + adaptive retry for low-output PRs.
    Phase 1: Same 8 lenses + strict validation as v11.
    Phase 2: If <=2 validated candidates, run a targeted "dig deeper" pass that
    asks the LLM to focus on categories it commonly misses (typos, concurrency,
    missing implementations) with the explicit instruction to find MORE bugs.
    This directly targets the 40/75 FNs in low-output PRs."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)
    rich_triage = build_rich_triage(entities) if entities else triage_section

