def detect_typo_patterns(entities: list[dict]) -> list[dict]:
    """Detect likely typos between entity names in the same PR using edit distance."""
    findings = []
    names = [(e.get("entity_name", ""), e.get("file_path", ""), e) for e in entities if e.get("change_type") in ("added", "modified")]
    for i, (name_a, fp_a, ent_a) in enumerate(names):
        if len(name_a) < 4:
            continue
        for j, (name_b, fp_b, ent_b) in enumerate(names):
            if j <= i or len(name_b) < 4:
                continue
            if name_a == name_b:
                continue
            # Simple edit distance: only check names within 1-2 edits and similar length
            if abs(len(name_a) - len(name_b)) > 2:
                continue
            diffs = sum(1 for a, b in zip(name_a.lower(), name_b.lower()) if a != b)
            diffs += abs(len(name_a) - len(name_b))
            if 1 <= diffs <= 2 and min(len(name_a), len(name_b)) >= 5:
                findings.append({
                    "type": "possible_typo",
                    "description": f"Possible typo: `{name_a}` (in {fp_a}) vs `{name_b}` (in {fp_b})",
                    "entity_name": name_a,
                    "file_path": fp_a,
                })
    return findings


def detect_import_issues(entities: list[dict], diff: str) -> list[dict]:
    """Detect new type references where corresponding import was removed."""
    findings = []
    # Find removed imports from the diff
    removed_imports = set()
    added_imports = set()
    for line in diff.split("\n"):
        if line.startswith("-") and not line.startswith("---"):
            m = re.search(r'(?:import|from|require|use)\s+.*?([A-Z]\w+)', line)
            if m:
                removed_imports.add(m.group(1))
        if line.startswith("+") and not line.startswith("+++"):
            m = re.search(r'(?:import|from|require|use)\s+.*?([A-Z]\w+)', line)
            if m:
                added_imports.add(m.group(1))

    truly_removed = removed_imports - added_imports
    if not truly_removed:
        return findings

    for ent in entities:
        if ent.get("change_type") not in ("modified", "added"):
            continue
        after = ent.get("after_content", "") or ""
        for imp in truly_removed:
            if re.search(r'\b' + re.escape(imp) + r'\b', after):
                findings.append({
                    "type": "missing_import",
                    "description": f"`{ent.get('entity_name', '?')}` in {ent.get('file_path', '?')} references `{imp}` but its import was removed",
                    "entity_name": ent.get("entity_name", "?"),
                    "file_path": ent.get("file_path", "?"),
                })
    return findings


def compute_entity_rank_score(e: dict) -> float:
    """Score entities for priority ranking in deterministic_v3."""
    score = e.get("risk_score", 0) or 0
    pats = e.get("_patterns", [])
    pat_types = len(set(p["type"] for p in pats))
    score += 0.15 * pat_types
    if e.get("before_content") and e.get("after_content"):
        score += 0.3
    # Public API bonus
    after = e.get("after_content", "") or ""
    before = e.get("before_content", "") or ""
    code = after or before
    if re.search(r'\b(public|export|pub)\b', code.split("\n")[0] if code else ""):
        score += 0.3
    if e.get("structural_change"):
        score += 0.2
    etype = e.get("entity_type", "").lower()
    if etype in ("method", "function"):
        score += 0.3
    elif etype in ("property", "variable"):
        score -= 0.1
    return score


# Stopwords for entity mention extraction (from heuristic_judge.py:extract_identifiers)
_ENTITY_STOPWORDS = {
    'the', 'this', 'that', 'with', 'from', 'will', 'can', 'may',
    'should', 'could', 'would', 'not', 'but', 'and', 'for', 'has',
    'have', 'been', 'being', 'are', 'was', 'were', 'because',
    'when', 'then', 'than', 'also', 'which', 'where', 'here',
    'there', 'into', 'only', 'instead', 'without', 'between',
    'during', 'using', 'after', 'before', 'other', 'method',
    'function', 'class', 'variable', 'parameter', 'returns',
    'called', 'calling', 'always', 'never', 'still', 'just',
    'like', 'some', 'any', 'all', 'each', 'both', 'same',
    'different', 'new', 'old', 'first', 'second', 'last',
    'however', 'since', 'further', 'consider', 'original',
    'issue', 'bug', 'error', 'test', 'check', 'code', 'value',
    'data', 'type', 'name', 'key', 'result', 'string', 'list',
    'null', 'none', 'true', 'false', 'set', 'get', 'add',
    'remove', 'create', 'update', 'delete', 'find', 'make',
    'call', 'run', 'use', 'missing', 'incorrect', 'wrong',
    'logic', 'potential', 'existing', 'current', 'causes',
    'causing', 'rather', 'whether', 'these', 'those', 'such',
    'what', 'does', 'how', 'its', 'might', 'already', 'directly',
    'immediately', 'properly', 'correctly', 'actually', 'specific',
    'possible', 'required', 'expected', 'necessary', 'even',
    'file', 'path', 'line', 'change', 'changed', 'removed',
    'added', 'modified', 'broken', 'break', 'breaks',
}


def extract_entity_mentions(text: str) -> list[str]:
    """Extract likely entity names from issue text. Priority: backtick > function() > PascalCase > camelCase > snake_case."""
    mentions = []
    seen = set()

    def _add(name):
        if name.lower() not in _ENTITY_STOPWORDS and name not in seen and len(name) >= 3:
            mentions.append(name)
            seen.add(name)

    # 1. Backtick-quoted
    for m in re.finditer(r'`([^`]+)`', text):
        val = m.group(1).strip()
        # Could be file path or code snippet, extract the function-like part
        if '(' in val:
            val = val.split('(')[0].rsplit('.', 1)[-1].strip()
        elif '/' in val or '\\' in val:
            continue  # Skip file paths
        _add(val)

    # 2. function() pattern
    for m in re.finditer(r'\b([a-zA-Z_]\w+)\s*\(', text):
        _add(m.group(1))

    # 3. PascalCase
    for m in re.finditer(r'\b([A-Z][a-z]+(?:[A-Z][a-z]+)+)\b', text):
        _add(m.group(1))

    # 4. camelCase
    for m in re.finditer(r'\b([a-z][a-zA-Z0-9]*[A-Z][a-zA-Z0-9]*)\b', text):
        _add(m.group(1))

    # 5. snake_case (must contain underscore)
    for m in re.finditer(r'\b([a-z][a-z0-9]*_[a-z0-9_]+)\b', text):
        _add(m.group(1))

    return mentions


def extract_file_mentions(text: str) -> list[str]:
    """Extract file path mentions from issue text."""
    files = []
    code_exts = (".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl", ".scss", ".css", ".properties")
    # Backtick-quoted paths
    for m in re.finditer(r'`([^`]+)`', text):
        val = m.group(1).strip()
        if any(val.endswith(ext) for ext in code_exts):
            files.append(val)
    # Bare path references
    for word in text.replace(",", " ").replace(")", " ").replace("(", " ").split():
        if any(word.endswith(ext) for ext in code_exts) and "/" in word:
            files.append(word)
    return files


def verify_issue_deterministic(issue: dict, entity_names_lower: set, diff_files_lower: set, entity_content_map: dict) -> dict:
    """Deterministically verify an LLM-reported issue against entity data. Returns scored issue."""
    score = 0
    file_val = issue.get("file", "")
    entity_val = issue.get("entity", "")
    desc = issue.get("description", "")
    full_text = f"{file_val} {entity_val} {desc}"

    # Try structured fields first, fall back to extraction from description
    file_mentions = [file_val] if file_val else extract_file_mentions(desc)
    entity_mentions = [entity_val] if entity_val else extract_entity_mentions(desc)

    # Check: file exists in diff
    file_verified = False
    for fm in file_mentions:
        fm_lower = fm.lower()
        fm_base = fm_lower.rsplit("/", 1)[-1]
        if fm_lower in diff_files_lower or fm_base in diff_files_lower:
            file_verified = True
            break
    if file_verified:
        score += 1

    # Check: entity exists in entity list
    entity_verified = False
    for em in entity_mentions:
        if em.lower() in entity_names_lower:
            entity_verified = True
            break
    if entity_verified:
        score += 1

    # Bonus: both file AND entity verified
    if file_verified and entity_verified:
        score += 1

    # Check: quoted code matches entity content
    backtick_quotes = re.findall(r'`([^`]+)`', desc)
    for quote in backtick_quotes:
        if len(quote) < 5:
            continue
        for content in entity_content_map.values():
            if quote in content:
                score += 1
                break
        break  # Only check first substantial quote

    # Penalty: speculative language
    spec_phrases = [
        "could potentially", "might lead", "hypothetically", "this is likely correct",
        "if any code relied", "this could", "might cause", "may potentially",
        "unclear whether", "it's possible that", "there may be",
    ]
    if any(p in desc.lower() for p in spec_phrases):
        score -= 1

    return {
        "description": desc,
        "file": file_val,
        "entity": entity_val,
        "score": score,
        "file_verified": file_verified,
        "entity_verified": entity_verified,
    }


async def review_deterministic_v3(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: deterministic_v3 - Maximum determinism, minimum LLM.
    Phase 1: Deterministic pattern detection + typo/import analysis (0 LLM)
    Phase 2: Single LLM review with structured output (1 LLM call, T=0, seed=42)
    Phase 3: Deterministic verification against entity data (0 LLM)"""
    provider = os.environ.get("REVIEW_PROVIDER", "openai")
    if provider == "anthropic":
        model = os.environ.get("REVIEW_MODEL", "claude-sonnet-4-5-20250929")
    else:
        model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)

    # Extract diff file paths for verification
    diff_files = set()
    for line in diff.split("\n"):
        if line.startswith("+++ b/") or line.startswith("--- a/"):
            path = line.split("/", 1)[1] if "/" in line else line[6:]
            if path and path != "/dev/null":
                diff_files.add(path)
                diff_files.add(path.rsplit("/", 1)[-1])

    diff_files_lower = {f.lower() for f in diff_files} | {f.lower().rsplit("/", 1)[-1] for f in diff_files}

    # === PHASE 1: Deterministic analysis ===
    all_entities = build_deterministic_entity_context(entities) if entities else []

    # New detectors
    typo_findings = detect_typo_patterns(all_entities)
    import_findings = detect_import_issues(all_entities, diff)

    entities_with_findings = [e for e in all_entities if e.get("_patterns")]
    total_findings = sum(len(e["_patterns"]) for e in entities_with_findings)

    # Cross-entity contract violations
    cross_findings = detect_cross_entity_issues(all_entities)

    # Build candidates from pattern findings
    candidates = []
    for ent in entities_with_findings:
        name = ent.get("entity_name", "?")
        fpath = ent.get("file_path", "?")
        for pat in ent["_patterns"]:
            candidates.append(f"In {fpath}, `{name}`: {pat['description']}")

    for f in cross_findings:
        candidates.append(f["finding"])
    for f in typo_findings:
        candidates.append(f["description"])
    for f in import_findings:
        candidates.append(f["description"])

    # Systematic refactor filter
    from collections import Counter
    pat_counts = Counter()
    for ent in entities_with_findings:
        for pat in ent["_patterns"]:
            pat_counts[pat["type"]] += 1
    before_filter = len(candidates)
    # Rebuild without systematic patterns
    filtered_candidates = []
    idx = 0
    for ent in entities_with_findings:
        for pat in ent["_patterns"]:
            if pat_counts[pat["type"]] < 8:
                filtered_candidates.append(candidates[idx])
            idx += 1
    # Cross/typo/import findings always pass
    filtered_candidates.extend(candidates[idx:])
    refactor_dropped = before_filter - len(filtered_candidates)
    candidates = filtered_candidates

    # Deprioritize test entities in ranking
    test_dirs = ("test", "tests", "spec", "testsuite", "testdata", "fixture", "fixtures", "__tests__", "__test__", "mock", "mocks")
    def is_test_file(path: str) -> bool:
        parts = path.lower().split("/")
        return any(p in test_dirs for p in parts) or any(path.lower().endswith(s) for s in ("_test.py", "_test.go", "_spec.rb", "test.java", "test.ts", "test.js", ".test.tsx", ".test.jsx", ".spec.ts", ".spec.js"))

    # Entity ranking for LLM context - deprioritize test files, boost impl
    def entity_rank_with_test_penalty(e):
        score = compute_entity_rank_score(e)
        # Bonus for language-specific patterns (high value signal)
        for p in e.get("_patterns", []):
            if p["type"] in ("async_foreach", "object_equality", "optional_get_unchecked", "mutable_default", "duplicate_method_def", "case_sensitivity_bypass", "lightness_inversion", "frozen_string_mutation", "react_missing_key", "empty_subclass", "dcl_missing_recheck", "invalid_end_if", "missing_predicate_suffix", "docstring_mismatch"):
                score += 0.5
                break
        if is_test_file(e.get("file_path", "")):
            score -= 0.5
        return score

    sorted_entities = sorted(all_entities, key=entity_rank_with_test_penalty, reverse=True)[:30]

    # Build entity names set and content map for verification
    entity_names_lower = {e.get("entity_name", "").lower() for e in all_entities if e.get("entity_name")}
    entity_content_map = {}
    for e in all_entities:
        name = e.get("entity_name", "")
        if name:
            content = (e.get("before_content", "") or "") + (e.get("after_content", "") or "")
            entity_content_map[name.lower()] = content

    # Build entity context for LLM - truncate to keep focus
    entity_parts = []
    for i, e in enumerate(sorted_entities):
        name = e.get("entity_name", "?")
        etype = e.get("entity_type", "?")
        fpath = e.get("file_path", "?")
        change = e.get("change_type", "?")
        char_limit = 1500 if i < 10 else 1000
        before = (e.get("before_content", "") or "")[:char_limit]
        after = (e.get("after_content", "") or "")[:char_limit]
        pats = ", ".join(p["type"] for p in e.get("_patterns", []))
        entity_parts.append(f"**`{name}`** ({etype}) in {fpath} [{change}]{' patterns: ' + pats if pats else ''}\nBEFORE:\n```\n{before}\n```\nAFTER:\n```\n{after}\n```")

    entity_context = "\n\n".join(entity_parts) if entity_parts else "(no entity data)"

    # Build high-confidence deterministic candidates for injection
    deterministic_candidates = []
    lang_pattern_types = {"async_foreach", "object_equality", "optional_get_unchecked", "mutable_default", "duplicate_method_def", "case_sensitivity_bypass", "lightness_inversion", "frozen_string_mutation", "react_missing_key", "empty_subclass", "dcl_missing_recheck", "invalid_end_if", "missing_predicate_suffix", "nondeterministic_hash", "broad_exception_catch", "invalid_vendor_prefix", "invalid_zod_schema", "nil_check_removed", "docstring_mismatch"}
    # High-confidence patterns get a stronger boost in scoring
    _high_confidence_patterns = {"async_foreach", "invalid_zod_schema", "missing_predicate_suffix", "duplicate_method_def"}
    for ent in entities_with_findings:
        name = ent.get("entity_name", "?")
        fpath = ent.get("file_path", "?")
        if is_test_file(fpath):
            continue
        for pat in ent["_patterns"]:
            if pat["type"] in lang_pattern_types:
                deterministic_candidates.append({
                    "file": fpath,
                    "entity": name,
                    "description": f"In `{fpath}`, `{name}`: {pat['description']}",
                    "_deterministic": True,
                    "_pattern_type": pat["type"],
                })

    # Pattern hints (non-lang patterns only, to avoid duplication)
    hint_text = ""
    non_lang_candidates = [c for c in candidates if not any(lt in c for lt in ("forEach with async", "=== comparing", "Optional.get()", "mutable", "defined multiple times", "case normalization", "lightness change", "frozen string", "missing key prop", "only 'pass'", "double-checked locking", "'end if'", "missing ? suffix", "non-deterministic", "broad exception", "vendor prefix", "Zod", "nil check", "typo in identifier", "return type annotation"))]
    if non_lang_candidates:
        hint_text = "\n## Static analysis hints (may contain false positives):\n" + "\n".join(f"- {c}" for c in non_lang_candidates[:25])

    print(f"[{len(all_entities)}ent,{total_findings}pat,{len(cross_findings)}xref,{len(typo_findings)}typo,{len(import_findings)}imp", end="", flush=True)
    if refactor_dropped:
        print(f",-{refactor_dropped}sys", end="", flush=True)
    print("]", end="", flush=True)

    # === PHASE 2: LLM review (3 parallel calls: data-flow + logic + cross-function) ===
    review_prompt = f"""PR Title: {pr_title}

## Changed entities with before/after code:
{entity_context}
{hint_text}

## Full PR Diff:
{truncated}

---
Find bugs INTRODUCED by this PR. For each changed entity, apply these analysis techniques:

**TRACE DATA FLOW:** What does each function return? Do callers handle it correctly? If a function now returns a raw Response instead of parsed data, callers accessing .data will break. If math.floor() receives a datetime instead of a number, it will throw TypeError.

**CHECK LOGIC:** Is each condition testing the right variable? Could any guard be always-true (making else branches unreachable)? Look for tautological comparisons, inverted booleans, and flipped ternaries.

**CHECK NAMES:** Scan new identifiers for typos ("santize" should be "sanitize", "inalid" should be "invalid"). Check if test method names match what they actually test (e.g., test named "empty_array" but tests empty dict). Typos in function names ARE bugs.

**CHECK SECURITY:** Unescaped user input in HTML (XSS). Static OAuth state parameters instead of per-request nonce (CSRF). X-Frame-Options: ALLOWALL (clickjacking). Regex patterns missing anchors (subdomain bypass). Case-sensitivity in auth validation.

**CHECK NULL SAFETY:** Were null/nil/None checks removed? Can parameters be null in some code path? (e.g., API key auth where user_id is None, pipeline state that may not exist)

**CHECK CONTRACTS:** When function signatures or return types change, are ALL callers updated? Check Zod schemas for wrong default values (literal string "refresh_token" instead of actual token). Check if migrations bypass model-level normalization.

**CHECK CONCURRENCY:** Read-modify-write without atomicity? Two concurrent requests could both pass a check (TOCTOU). Shared mutable state without locks.

**CHECK DEAD CODE:** Unreachable branches after always-true conditions. Imports of symbols that don't exist. Computed results that are never used. Error messages that describe the wrong operation.

For each bug, name the EXACT file path and entity (function/method/class name).
ONLY report bugs introduced by THIS PR. Not style, not pre-existing.
Report 0-10 bugs. Each must WILL cause wrong behavior, a crash, or a security issue.

Respond with ONLY a JSON array (no wrapping object):
[{{"file": "path/to/file.ext", "entity": "functionName", "description": "what breaks and why"}}]
If no bugs: []"""

    # Separate prompt for logic specialist (Call 3)
    logic_prompt = f"""PR Title: {pr_title}

## Changed entities with before/after code:
{entity_context}

## Full PR Diff:
{truncated}

---
Find LOGIC and TYPE bugs ONLY in this PR. For each changed entity, carefully trace:

1. Is each condition testing the RIGHT variable? (common bug: checking variable X when Y is what matters)
2. Can any condition be always-true or always-false? (e.g., function always returns non-null, so null-check branch is dead code)
3. Are there inverted booleans or flipped ternaries? (slug set when billing IS enabled instead of when it's NOT)
4. When function A's return type or behavior changed, do all callers of A still work correctly?
5. Does any code call math operations on non-numeric types, or access properties that don't exist on the actual type?
6. Are there read-modify-write sequences without atomicity that allow concurrent requests to both pass?
7. Do error messages, docstrings, or test names accurately describe what the code actually does?

Report 0-5 logic/type bugs. Each must WILL cause wrong behavior.

Respond with ONLY a JSON array:
[{{"file": "path/to/file.ext", "entity": "functionName", "description": "the logic/type error and what breaks"}}]
If no bugs: []"""

    def parse_structured_response(content: str) -> list[dict]:
        content = content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        parsed = json.loads(content)
        if isinstance(parsed, list):
            items = parsed
        elif isinstance(parsed, dict) and "issues" in parsed:
            items = parsed["issues"]
        else:
            return []
        normalized = []
        for item in items:
            if isinstance(item, str):
                normalized.append({"file": "", "entity": "", "description": item})
            elif isinstance(item, dict):
                normalized.append({
                    "file": item.get("file", ""),
                    "entity": item.get("entity", ""),
                    "description": item.get("description", str(item)),
                })
        return normalized

    llm_timeout = 300 if provider == "anthropic" else 180
    llm_issues = []
    try:
        task1 = asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a senior code reviewer who finds bugs by tracing data flow. For each changed function: (1) identify return type and check if callers handle it correctly, (2) when signatures change, verify every caller passes right args, (3) check type compatibility at every step (datetime vs number, Response vs parsed data), (4) check for removed null/None/nil checks that leave downstream code unprotected. Only report bugs that WILL cause wrong behavior. Name exact files and functions. Respond with ONLY a JSON array."},
                    {"role": "user", "content": review_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=llm_timeout,
        )
        task2 = asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a senior code reviewer who finds bugs in logic and naming. For each entity: (1) check conditions for inversions, always-true/false guards, tautological comparisons, (2) check branch reachability - if a function always returns non-null, the null-check else branch is dead, (3) check new identifiers for typos - typos in function names ARE real bugs, (4) check security: unescaped HTML interpolation, static OAuth state, permissive X-Frame-Options, regex without anchors. Only report bugs that WILL cause wrong behavior. Respond with ONLY a JSON array."},
                    {"role": "user", "content": review_prompt},
                ],
                temperature=0.3,
                seed=123,
            ),
            timeout=llm_timeout,
        )
        task3 = asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a code reviewer specializing in subtle cross-function bugs. Focus on: (1) read operations with hidden write side effects, (2) case-sensitive comparisons where case-insensitive is needed, (3) migrations bypassing model validation, (4) race conditions and TOCTOU, (5) error messages/docstrings that don't match the actual operation. Only report concrete bugs. Respond with ONLY a JSON array."},
                    {"role": "user", "content": logic_prompt},
                ],
                temperature=0.0,
                seed=7,
            ),
            timeout=llm_timeout,
        )
        results = await asyncio.gather(task1, task2, task3, return_exceptions=True)
        for r in results:
            if isinstance(r, Exception):
                print(f"[t-err:{r.__class__.__name__}]", end="", flush=True)
            else:
                llm_issues.extend(parse_structured_response(r.choices[0].message.content))
    except Exception as e:
        print(f"[llm-err:{e.__class__.__name__}]", end="", flush=True)

    print(f"[{len(llm_issues)}llm]", end="", flush=True)

    if deterministic_candidates:
        print(f"[+{len(deterministic_candidates)}det]", end="", flush=True)

    # Merge all candidates
    all_candidates = llm_issues + deterministic_candidates

    # DEBUG: save all LLM-generated issues before any filtering
    _debug_stages = {
        "phase1_entities": [
            {
                "entity_name": e.get("entity_name", "?"),
                "entity_type": e.get("entity_type", "?"),
                "file_path": e.get("file_path", "?"),
                "change_type": e.get("change_type", "?"),
                "patterns": [p["type"] + ": " + p["description"][:100] for p in e.get("_patterns", [])],
            }
            for e in all_entities
        ],
        "phase1_patterns_summary": {
            "total_entities": len(all_entities),
            "total_patterns": total_findings,
            "cross_entity_issues": len(cross_findings),
            "typo_findings": len(typo_findings),
            "import_findings": len(import_findings),
            "refactor_dropped": refactor_dropped,
            "deterministic_candidates": len(deterministic_candidates),
        },
        "phase2_llm_raw": [i.get("description", str(i))[:200] for i in llm_issues],
        "phase2_det_raw": [i.get("description", str(i))[:200] for i in deterministic_candidates],
    }

    if not all_candidates:
        _debug_stages["phase3_scored"] = []
        _debug_stages["phase3_to_verify"] = []
        _debug_stages["phase4_verified"] = []
        review_deterministic_v3._last_debug = _debug_stages
        return []

    # === PHASE 3: Deterministic pre-filter ===
    # Dedup by first 80 chars of description
    seen = set()
    deduped = []
    for issue in all_candidates:
        key = issue["description"].lower()[:80]
        if key not in seen:
            deduped.append(issue)
            seen.add(key)

    # Score each issue deterministically
    scored = []
    for issue in deduped:
        result = verify_issue_deterministic(issue, entity_names_lower, diff_files_lower, entity_content_map)
        # Tiered boost for deterministic candidates (already entity-grounded)
        if issue.get("_deterministic"):
            if issue.get("_pattern_type") in _high_confidence_patterns:
                result["score"] += 2
            else:
                result["score"] += 1
        scored.append(result)

    # Structural file filter
    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl", ".scss", ".css", ".properties"}
        filtered = []
        dropped = 0
        for v in scored:
            text = v["description"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in diff_files_lower:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(v)
        if dropped:
            print(f"[-{dropped}f]", end="", flush=True)
        scored = filtered

    # Drop speculative language deterministically
    spec_phrases = ["could potentially", "might lead", "this is likely correct", "if any code relied", "hypothetically"]
    scored = [v for v in scored if not any(p in v["description"].lower() for p in spec_phrases)]

    # Sort by score descending
    scored.sort(key=lambda x: x["score"], reverse=True)
    _debug_stages["phase3_scored"] = [f"[s={v['score']}] {v['description'][:200]}" for v in scored]

    to_verify = scored[:9]
    _debug_stages["phase3_to_verify"] = [f"[s={v['score']}] {v['description'][:200]}" for v in to_verify]
    _debug_stages["phase3_cut_by_top9"] = [f"[s={v['score']}] {v['description'][:200]}" for v in scored[9:]]

    if not to_verify:
        return []

    # === PHASE 4: LLM verification (1 call) ===
    candidates_list = "\n".join(f"{i+1}. {v['description']}" for i, v in enumerate(to_verify))

    verify_prompt = f"""PR Title: {pr_title}

## Candidate issues:
{candidates_list}

## Full PR Diff:
{truncated}

---
STEP 1: Verify each candidate against the actual diff:
1. Does the specific code mentioned actually exist in the diff? If not, DROP it.
2. Is this a concrete bug that WILL cause wrong behavior, a crash, or a security issue? If purely speculative ("could potentially", "might lead to"), DROP it.
3. Is the old behavior being clearly replaced by equivalent new code elsewhere in the diff? If clearly yes, DROP it.

IMPORTANT: DO keep these types of issues - they are real bugs:
- Typos in function/method/class names (break callers, confuse maintainers)
- Wrong variable or parameter names (cause wrong behavior)
- Test names that don't match test behavior (test coverage gaps)
- Missing null/nil/None checks (cause crashes)
- Case-sensitivity mismatches in validation (bypass vulnerabilities)
- Error messages describing the wrong operation (mislead debugging)

STEP 2: Check the diff for important bugs NOT in the candidate list:
- Logic errors: inverted conditions, always-true guards making branches unreachable
- Type mismatches: datetime where number expected, Response where parsed data expected
- API contract breaks: return type or signature changed but callers not updated
- Null safety: removed null checks, new paths receiving null
- Naming: typos in new identifiers, test names not matching behavior
- Security: unescaped HTML interpolation, static OAuth state, permissive frame options

Return ONLY confirmed real bugs (both verified and newly found). For each, name the function, file, and exact failure.

Respond with ONLY: {{"issues": ["description1", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are doing final verification of code review findings. Keep issues you can confirm against the diff. Typos in identifiers, missing null checks, and naming mismatches ARE real bugs - do not drop them as style issues. Always respond with valid JSON."},
                    {"role": "user", "content": verify_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=llm_timeout,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        verified = json.loads(content).get("issues", [])
        verified = [i for i in verified if isinstance(i, str)]
    except Exception as e:
        print(f"[vfy-err:{e.__class__.__name__}]", end="", flush=True)
        verified = [v["description"] for v in to_verify[:5]]

    # Post-verification speculative filter
    spec_phrases = ["could potentially", "might lead", "this is likely correct", "if any code relied", "hypothetically", "may cause issues", "could cause", "if this is used", "depending on how"]
    verified = [v for v in verified if not any(p in v.lower() for p in spec_phrases)]

    # Dedup final output - first pass: exact prefix
    seen_final = set()
    deduped_final = []
    for v in verified:
        key = v.lower()[:80]
        if key not in seen_final:
            deduped_final.append(v)
            seen_final.add(key)

    # Semantic dedup: if two candidates describe the same bug pattern in different
    # files/entities, keep only the first (highest-confidence) one.
    # Uses word overlap minus file paths and entity names (structural words only).
    import re as _re
    def _structural_words(text: str) -> set:
        """Extract bug-description words, stripping file paths and backtick-quoted identifiers."""
        # Remove file paths (foo/bar/baz.ext)
        t = _re.sub(r'[\w./\\-]+\.\w{1,4}', '', text.lower())
        # Remove backtick-quoted code
        t = _re.sub(r'`[^`]+`', '', t)
        # Keep only alpha words of 4+ chars (skip short words, numbers)
        return {w for w in _re.findall(r'[a-z]{4,}', t)}

    sem_deduped = []
    sem_dropped = 0
    for i, v in enumerate(deduped_final):
        v_words = _structural_words(v)
        is_dup = False
        for prev in sem_deduped:
            prev_words = _structural_words(prev)
            if not v_words or not prev_words:
                continue
            overlap = len(v_words & prev_words) / min(len(v_words), len(prev_words))
            if overlap > 0.6:
                is_dup = True
                break
        if is_dup:
            sem_dropped += 1
        else:
            sem_deduped.append(v)
    if sem_dropped:
        print(f"[-{sem_dropped}dup]", end="", flush=True)
    deduped_final = sem_deduped

    print(f"[{len(deduped_final)}fin]", end="", flush=True)

    _debug_stages["phase4_verified_raw"] = verified[:20]
    _debug_stages["phase4_final"] = deduped_final[:7]
    review_deterministic_v3._last_debug = _debug_stages

    return deduped_final[:7]


def build_entity_diff(entities: list[dict], total_budget: int = 80_000, raw_diff: str = "") -> str:
    """Generate a unified diff from entity before/after content, then fill gaps from raw diff.
    Entity diffs get 60% of budget. Raw diff gap-fill gets the rest. No duplication."""
    import difflib
    if not entities and not raw_diff:
        return ""

    entity_budget = total_budget

    # --- Phase 1: Build entity diff ---
    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")] if entities else []

    # Skip parent entities when children exist in the same file
    parent_types = {"class", "interface", "struct", "module", "impl"}
    by_file_types = {}
    for e in meaningful:
        fp = e.get("file_path", "")
        by_file_types.setdefault(fp, set()).add(e.get("entity_type", ""))

    filtered = []
    for e in meaningful:
        fp = e.get("file_path", "")
        etype = e.get("entity_type", "")
        file_types = by_file_types.get(fp, set())
        if etype in parent_types and (file_types - parent_types - {"chunk"}):
            continue
        filtered.append(e)

    filtered.sort(key=lambda e: e.get("risk_score", 0), reverse=True)

    by_file = {}
    for e in filtered:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    # We'll collect the actual +/- lines emitted by entity diffs for dedup
    entity_diff_lines = set()

    total_chars = 0
    parts = []
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        if total_chars >= entity_budget:
            break
        file_diff_lines = [f"diff --git a/{fp} b/{fp}", f"--- a/{fp}", f"+++ b/{fp}"]
        for e in ents:
            if total_chars >= entity_budget:
                break
            before = e.get("before_content", "") or ""
            after = e.get("after_content", "") or ""
            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            start = e.get("start_line", 1)

            if e.get("change_type") == "added":
                added_lines = after.splitlines()
                file_diff_lines.append(f"@@ -0,0 +{start},{len(added_lines)} @@ {etype}: {name}")
                for line in added_lines:
                    file_diff_lines.append(f"+{line}")
                    entity_diff_lines.add(line.strip())
                total_chars += len(after)
            elif before and after:
                diff_lines = list(difflib.unified_diff(
                    before.splitlines(), after.splitlines(),
                    lineterm="", n=3
                ))
                if len(diff_lines) > 2:
                    file_diff_lines.append(f"@@ entity: {etype} {name} @@")
                    for line in diff_lines[2:]:
                        file_diff_lines.append(line)
                        if line.startswith("+") or line.startswith("-"):
                            entity_diff_lines.add(line[1:].strip())
                    total_chars += sum(len(l) for l in diff_lines[2:])
            elif after:
                added_lines = after.splitlines()
                file_diff_lines.append(f"@@ -0,0 +{start},{len(added_lines)} @@ {etype}: {name}")
                for line in added_lines:
                    file_diff_lines.append(f"+{line}")
                    entity_diff_lines.add(line.strip())
                total_chars += len(after)

        if len(file_diff_lines) > 3:
            parts.append("\n".join(file_diff_lines))

    # --- Phase 2: Fill gaps from raw diff ---
    if raw_diff:
        raw_sections = raw_diff.split("diff --git ")
        for section in raw_sections[1:]:
            if total_chars >= total_budget:
                break
            lines = section.split("\n")
            # Collect changed lines in this section that entity content doesn't cover
            gap_lines = []
            in_hunk = False
            for line in lines:
                if line.startswith("@@"):
                    in_hunk = True
                    gap_lines.append(line)
                    continue
                if not in_hunk:
                    gap_lines.append(line)  # headers
                    continue
                if line.startswith("+") or line.startswith("-"):
                    content = line[1:].strip()
                    if content and content not in entity_diff_lines:
                        gap_lines.append(line)
                elif line.startswith(" "):
                    gap_lines.append(line)  # context lines

            # Check if this section has any novel changed lines
            novel_changes = sum(1 for l in gap_lines if (l.startswith("+") or l.startswith("-"))
                                and not l.startswith("+++") and not l.startswith("---"))
            if novel_changes > 0:
                chunk = "diff --git " + "\n".join(gap_lines)
                if total_chars + len(chunk) <= total_budget:
                    parts.append(chunk)
                    total_chars += len(chunk)

    return "\n".join(parts)


def build_entity_content_triage(entities: list[dict], max_entity_chars: int = 4000, total_budget: int = 100_000) -> str:
    """Build triage section with actual before/after entity code content instead of raw diff."""
    if not entities:
        return ""

    meaningful = [e for e in entities if e.get("change_type") in ("modified", "added")
                  and e.get("entity_type") not in ("chunk",)]
    meaningful.sort(key=lambda e: e.get("risk_score", 0), reverse=True)
    top = meaningful[:30]

    if not top:
        return ""

    by_file = {}
    for e in top:
        fp = e.get("file_path", "")
        by_file.setdefault(fp, []).append(e)

    total_chars = 0
    lines = ["## Entity-level changes (highest-risk first):"]
    for fp, ents in sorted(by_file.items(), key=lambda x: max(e.get("risk_score", 0) for e in x[1]), reverse=True):
        lines.append(f"\n### {fp}")
        for e in ents:
            if total_chars >= total_budget:
                lines.append("\n(remaining entities omitted for length)")
                return "\n".join(lines)

            name = e.get("entity_name", "?")
            etype = e.get("entity_type", "?")
            change = e.get("change_type", "?")
            classification = e.get("classification", "?")
            public = " [PUBLIC API]" if e.get("is_public_api") else ""
            start = e.get("start_line", "?")
            end = e.get("end_line", "?")
            lines.append(f"\n**{name} ({etype}, {change}, {classification}){public}** (lines {start}-{end}):")

            before = e.get("before_content", "")
            after = e.get("after_content", "")

            if change == "modified":
                if before:
                    capped = before[:max_entity_chars]
                    if len(before) > max_entity_chars:
                        nl = capped.rfind("\n")
                        if nl > 0:
                            capped = capped[:nl]
                        capped += "...(truncated)"
                    lines.append(f"Before:\n```\n{capped}\n```")
                    total_chars += len(capped)
                if after:
                    capped = after[:max_entity_chars]
                    if len(after) > max_entity_chars:
                        nl = capped.rfind("\n")
                        if nl > 0:
                            capped = capped[:nl]
                        capped += "...(truncated)"
                    lines.append(f"After:\n```\n{capped}\n```")
                    total_chars += len(capped)
            elif change == "added":
                if after:
                    capped = after[:max_entity_chars]
                    if len(after) > max_entity_chars:
                        nl = capped.rfind("\n")
                        if nl > 0:
                            capped = capped[:nl]
                        capped += "...(truncated)"
                    lines.append(f"Added:\n```\n{capped}\n```")
                    total_chars += len(capped)

    return "\n".join(lines)


async def review_entity_only_v1(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: entity_only_v1 - v19 architecture but with entity content instead of raw diff.
    Tests whether entity-level before/after content can replace the raw git diff entirely.
    Same 9 lenses, same structural filter, same validation. Only difference: no raw diff."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    entity_triage = build_entity_content_triage(entities) if entities else triage_section

    # Extract file paths from entities for structural filter (instead of from diff)
    diff_files = set()
    if entities:
        for e in entities:
            fp = e.get("file_path", "")
            if fp:
                diff_files.add(fp)
                diff_files.add(fp.rsplit("/", 1)[-1])

    async def run_lens(system_msg: str, prompt: str, temp: float, seed: int = 42) -> list[dict]:
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": system_msg},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=temp,
                    seed=seed,
                ),
                timeout=180,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            items = json.loads(content).get("issues", [])
            result = []
            for item in items:
                if isinstance(item, str):
                    result.append({"issue": item, "evidence": ""})
                elif isinstance(item, dict):
                    result.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})
            return result
        except Exception as e:
            print(f"[lens-err:{e}]", end="", flush=True)
            return []

    # Same 6 specialized + 1 general + 2 diversity lenses as v19, but entity_triage instead of truncated diff
    prompt_data = f"""You are a code reviewer specializing in DATA CORRECTNESS issues.

PR Title: {pr_title}
{entity_triage}

Focus ONLY on: wrong translations, wrong constants/mappings/enum values, copy-paste errors, wrong key/field references, case sensitivity in comparisons, incorrect regex.
Rules: ONLY concrete data issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_concurrency = f"""You are a code reviewer specializing in CONCURRENCY and STATE bugs.

PR Title: {pr_title}
{entity_triage}

Focus ONLY on: race conditions, missing locks/transactions, stale reads, process lifecycle bugs, cache inconsistency, feature flag inconsistency.
Rules: ONLY issues with evidence in the code. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_contracts = f"""You are a code reviewer specializing in API CONTRACT violations.

PR Title: {pr_title}
{entity_triage}

Focus ONLY on: missing abstract method implementations, wrong signatures/types, API breaking changes, wrong parameter order, key mismatches, missing React keys, import errors, method name typos breaking interfaces.
Rules: ONLY verifiable issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_security = f"""You are a security-focused code reviewer.

PR Title: {pr_title}
{entity_triage}

Focus ONLY on: SSRF, XSS, injection, auth bypass, origin/referrer bypass, case sensitivity bypass in security comparisons, frame options misconfig, hardcoded secrets.
Rules: ONLY real exploitable vulnerabilities. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_typos = f"""You are a code reviewer with exceptional attention to character-level detail.

PR Title: {pr_title}
{entity_triage}

Focus ONLY on:
- Method/function/variable name TYPOS causing runtime errors
- Wrong language in locale/translation files
- Missing required method suffixes (Rails '?', etc.)
- Case sensitivity bugs in comparisons
- Wrong vendor prefixes
- Property/key name mismatches

Rules: Character-level precision. Only if it causes runtime failure. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_runtime = f"""You are a code reviewer focused on RUNTIME FAILURES.

PR Title: {pr_title}
{entity_triage}

For each changed function/class, ask: "What would happen if I ran this code?"

Focus ONLY on:
- Null/nil/undefined dereference
- Missing abstract method implementations causing TypeError
- Unreachable code branches
- Infinite recursion without termination
- Wrong error messages
- Panic on nil in Go
- Missing React keys

Rules: RUNTIME behavior only. Only actual failures. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_general = f"""You are a world-class code reviewer. Review this PR and find ONLY real, concrete bugs.

PR Title: {pr_title}

{entity_triage}

Look specifically for these categories of issues:
1. Logic errors: wrong conditions, off-by-one, incorrect algorithms, broken control flow, inverted booleans
2. Concurrency bugs: race conditions, missing locks, unsafe shared state, deadlocks, unhandled async promises
3. Null/undefined safety: missing null checks, possible NPE, Optional.get() without isPresent(), uninitialized variables
4. Error handling: swallowed exceptions, missing error propagation, wrong error types
5. Data correctness: wrong translations, wrong constants, incorrect mappings, copy-paste errors, stale cache data
6. Security: SSRF, XSS, injection, auth bypass, exposed secrets, unsafe deserialization, origin validation bypass
7. Type mismatches: wrong return types, incompatible casts, API contract violations, schema errors
8. Breaking changes: removed public APIs without migration, changed behavior silently
9. State consistency: asymmetric cache trust, orphaned data, inconsistent updates across related fields
10. Naming/contract bugs: method name typos that break interfaces, property names that don't match expected contracts

Rules:
- ONLY report issues you are highly confident about (>90% sure)
- Be specific: name the file, function/variable, and exactly what's wrong
- Naming typos ARE bugs if they would cause a runtime error or break an API contract
- Do NOT report: style preferences, missing tests, docs, "could be improved"
- Do NOT report issues about code that was only deleted/removed
- Maximum 10 issues. Quality over quantity.

For each issue, provide it as a JSON object with "issue" (description) and "evidence" (quote the specific code lines that prove this is a bug).

Respond with ONLY a JSON object:
{{"issues": [{{"issue": "description", "evidence": "the specific code"}}]}}"""

    sys_precise = "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."

    # 9 lenses: 6 specialized@T=0 + 1 general@T=0 + 2 general@T=0.3 (different seeds)
    results = await asyncio.gather(
        run_lens("You are a data correctness reviewer. Always respond with valid JSON.", prompt_data, 0.0),
        run_lens("You are a concurrency/state bug reviewer. Always respond with valid JSON.", prompt_concurrency, 0.0),
        run_lens("You are an API contracts reviewer. Always respond with valid JSON.", prompt_contracts, 0.0),
        run_lens("You are a security reviewer. Always respond with valid JSON.", prompt_security, 0.0),
        run_lens("You are a character-level detail reviewer. Always respond with valid JSON.", prompt_typos, 0.0),
        run_lens("You are a runtime failure analyst. Always respond with valid JSON.", prompt_runtime, 0.0),
        run_lens(sys_precise, prompt_general, 0.0),
        run_lens(sys_precise, prompt_general, 0.3, seed=42),
        run_lens(sys_precise, prompt_general, 0.3, seed=123),
    )

    # Merge + dedup
    all_issues = []
    existing_lower = set()
    for pass_result in results:
        for s in pass_result:
            key = s["issue"].lower()[:80]
            if key not in existing_lower:
                all_issues.append(s)
                existing_lower.add(key)

    if not all_issues:
        return []

    # Structural file filter
    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl"}
        filtered = []
        dropped = 0
        for s in all_issues:
            text = s["issue"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in {f.lower().rsplit("/", 1)[-1] for f in diff_files}:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(s)
        if dropped:
            print(f"[-{dropped}file]", end="", flush=True)
        all_issues = filtered

    if not all_issues:
        return []

    print(f"[{len(all_issues)} raw]", end="", flush=True)

    # Validate with entity content (no diff)
    candidates_text = "\n".join(
        f"{i+1}. {s['issue']}" + (f"\n   Evidence: {s['evidence']}" if s['evidence'] else "")
        for i, s in enumerate(all_issues)
    )

    refine_prompt = f"""You are a senior code reviewer doing final validation. You have entity-level code changes and candidate issues.

PR Title: {pr_title}

{entity_triage}

Candidate Issues:
{candidates_text}

For each candidate, verify against the entity code above:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.

Return ONLY the issues that are verified real bugs with evidence in the code.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the entity-level code changes. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=180,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"[val-err:{e.__class__.__name__}]", end="", flush=True)
        return [s["issue"] for s in all_issues[:5]]


async def review_entity_only_v2(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: entity_only_v2 - v19 but with entity-generated unified diff instead of raw git diff.
    Same 9 lenses, same structural filter, same validation.
    The diff is generated from entity before/after content using difflib, giving +/- markers."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    # Generate diff from entity content, fill gaps from raw diff
    entity_diff = build_entity_diff(entities, raw_diff=diff) if entities else diff
    truncated = truncate_diff(entity_diff, max_chars=80000)
    rich_triage = build_rich_triage(entities) if entities else triage_section

    # Extract file paths from entities for structural filter
    diff_files = set()
    if entities:
        for e in entities:
            fp = e.get("file_path", "")
            if fp:
                diff_files.add(fp)
                diff_files.add(fp.rsplit("/", 1)[-1])

    async def run_lens(system_msg: str, prompt: str, temp: float, seed: int = 42) -> list[dict]:
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": system_msg},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=temp,
                    seed=seed,
                ),
                timeout=180,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            items = json.loads(content).get("issues", [])
            result = []
            for item in items:
                if isinstance(item, str):
                    result.append({"issue": item, "evidence": ""})
                elif isinstance(item, dict):
                    result.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})
            return result
        except Exception as e:
            print(f"[lens-err:{e}]", end="", flush=True)
            return []

    # Same prompts as v19 but using entity-generated diff
    prompt_data = f"""You are a code reviewer specializing in DATA CORRECTNESS issues.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: wrong translations, wrong constants/mappings/enum values, copy-paste errors, wrong key/field references, case sensitivity in comparisons, incorrect regex.
Rules: ONLY concrete data issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_concurrency = f"""You are a code reviewer specializing in CONCURRENCY and STATE bugs.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: race conditions, missing locks/transactions, stale reads, process lifecycle bugs, cache inconsistency, feature flag inconsistency.
Rules: ONLY issues with evidence in the diff. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_contracts = f"""You are a code reviewer specializing in API CONTRACT violations.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: missing abstract method implementations, wrong signatures/types, API breaking changes, wrong parameter order, key mismatches, missing React keys, import errors, method name typos breaking interfaces.
Rules: ONLY verifiable issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_security = f"""You are a security-focused code reviewer.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on: SSRF, XSS, injection, auth bypass, origin/referrer bypass, case sensitivity bypass in security comparisons, frame options misconfig, hardcoded secrets.
Rules: ONLY real exploitable vulnerabilities. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_typos = f"""You are a code reviewer with exceptional attention to character-level detail.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

Focus ONLY on:
- Method/function/variable name TYPOS causing runtime errors
- Wrong language in locale/translation files
- Missing required method suffixes (Rails '?', etc.)
- Case sensitivity bugs in comparisons
- Wrong vendor prefixes
- Property/key name mismatches

Rules: Character-level precision. Only if it causes runtime failure. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_runtime = f"""You are a code reviewer focused on RUNTIME FAILURES.

PR Title: {pr_title}
{rich_triage}
PR Diff:
{truncated}

For each changed function/class, ask: "What would happen if I ran this code?"

Focus ONLY on:
- Null/nil/undefined dereference
- Missing abstract method implementations causing TypeError
- Unreachable code branches
- Infinite recursion without termination
- Wrong error messages
- Panic on nil in Go
- Missing React keys

Rules: RUNTIME behavior only. Only actual failures. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_general = PROMPT_DEEP.format(pr_title=pr_title, triage_section=rich_triage, diff=truncated)
    sys_precise = "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."

    # 9 lenses: 6 specialized@T=0 + 1 general@T=0 + 2 general@T=0.3 (different seeds)
    results = await asyncio.gather(
        run_lens("You are a data correctness reviewer. Always respond with valid JSON.", prompt_data, 0.0),
        run_lens("You are a concurrency/state bug reviewer. Always respond with valid JSON.", prompt_concurrency, 0.0),
        run_lens("You are an API contracts reviewer. Always respond with valid JSON.", prompt_contracts, 0.0),
        run_lens("You are a security reviewer. Always respond with valid JSON.", prompt_security, 0.0),
        run_lens("You are a character-level detail reviewer. Always respond with valid JSON.", prompt_typos, 0.0),
        run_lens("You are a runtime failure analyst. Always respond with valid JSON.", prompt_runtime, 0.0),
        run_lens(sys_precise, prompt_general, 0.0),
        run_lens(sys_precise, prompt_general, 0.3, seed=42),
        run_lens(sys_precise, prompt_general, 0.3, seed=123),
    )

    # Merge + dedup
    all_issues = []
    existing_lower = set()
    for pass_result in results:
        for s in pass_result:
            key = s["issue"].lower()[:80]
            if key not in existing_lower:
                all_issues.append(s)
                existing_lower.add(key)

    if not all_issues:
        return []

    # Structural file filter
    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl"}
        filtered = []
        dropped = 0
        for s in all_issues:
            text = s["issue"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in {f.lower().rsplit("/", 1)[-1] for f in diff_files}:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(s)
        if dropped:
            print(f"[-{dropped}file]", end="", flush=True)
        all_issues = filtered

    if not all_issues:
        return []

    print(f"[{len(all_issues)} raw]", end="", flush=True)

    # Validate with entity-generated diff
    candidates_text = "\n".join(
        f"{i+1}. {s['issue']}" + (f"\n   Evidence: {s['evidence']}" if s['evidence'] else "")
        for i, s in enumerate(all_issues)
    )

    refine_prompt = f"""You are a senior code reviewer doing final validation. You have the PR diff and candidate issues.

PR Title: {pr_title}

PR Diff (for verification):
{truncated}

Candidate Issues:
{candidates_text}

For each candidate, verify against the actual diff:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.

Return ONLY the issues that are verified real bugs with evidence in the diff.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the actual diff. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=180,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"[val-err:{e.__class__.__name__}]", end="", flush=True)
        return [s["issue"] for s in all_issues[:5]]


async def review_deterministic_v4(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: deterministic_v4 - v3 + 3 specialized entity-aware lenses.
    Phase 1: Same deterministic analysis as v3
    Phase 2: 5 parallel LLM calls (2 general + 3 specialized), all seeing entity context
    Phase 3: Same deterministic scoring
    Phase 4: LLM verification + discovery
    Total: 6 LLM calls per PR (5 review + 1 verify)"""
    provider = os.environ.get("REVIEW_PROVIDER", "openai")
    if provider == "anthropic":
        model = os.environ.get("REVIEW_MODEL", "claude-sonnet-4-5-20250929")
    else:
        model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)

    diff_files = set()
    for line in diff.split("\n"):
        if line.startswith("+++ b/") or line.startswith("--- a/"):
            path = line.split("/", 1)[1] if "/" in line else line[6:]
            if path and path != "/dev/null":
                diff_files.add(path)
                diff_files.add(path.rsplit("/", 1)[-1])
    diff_files_lower = {f.lower() for f in diff_files} | {f.lower().rsplit("/", 1)[-1] for f in diff_files}

    # === PHASE 1: Same deterministic analysis as v3 ===
    all_entities = build_deterministic_entity_context(entities) if entities else []
    typo_findings = detect_typo_patterns(all_entities)
    import_findings = detect_import_issues(all_entities, diff)
    entities_with_findings = [e for e in all_entities if e.get("_patterns")]
    total_findings = sum(len(e["_patterns"]) for e in entities_with_findings)
    cross_findings = detect_cross_entity_issues(all_entities)

    candidates = []
    for ent in entities_with_findings:
        name = ent.get("entity_name", "?")
        fpath = ent.get("file_path", "?")
        for pat in ent["_patterns"]:
            candidates.append(f"In {fpath}, `{name}`: {pat['description']}")
    for f in cross_findings:
        candidates.append(f["finding"])
    for f in typo_findings:
        candidates.append(f["description"])
    for f in import_findings:
        candidates.append(f["description"])

    from collections import Counter
    pat_counts = Counter()
    for ent in entities_with_findings:
        for pat in ent["_patterns"]:
            pat_counts[pat["type"]] += 1
    before_filter = len(candidates)
    filtered_candidates = []
    idx = 0
    for ent in entities_with_findings:
        for pat in ent["_patterns"]:
            if idx < len(candidates) and pat_counts[pat["type"]] >= 5:
                pass
            elif idx < len(candidates):
                filtered_candidates.append(candidates[idx])
            idx += 1
    filtered_candidates.extend(candidates[idx:])
    refactor_dropped = before_filter - len(filtered_candidates)
    candidates = filtered_candidates

    test_dirs = ("test", "tests", "spec", "testsuite", "testdata", "fixture", "fixtures", "__tests__", "__test__", "mock", "mocks")
    def is_test_file(path: str) -> bool:
        parts = path.lower().split("/")
        return any(p in test_dirs for p in parts) or any(path.lower().endswith(s) for s in ("_test.py", "_test.go", "_spec.rb", "test.java", "test.ts", "test.js", ".test.tsx", ".test.jsx", ".spec.ts", ".spec.js"))

    lang_pattern_types = {"async_foreach", "object_equality", "optional_get_unchecked", "mutable_default", "duplicate_method_def", "case_sensitivity_bypass", "lightness_inversion", "frozen_string_mutation", "react_missing_key", "empty_subclass", "dcl_missing_recheck", "invalid_end_if", "missing_predicate_suffix", "nondeterministic_hash", "broad_exception_catch", "invalid_vendor_prefix", "invalid_zod_schema", "nil_check_removed", "docstring_mismatch"}
    _high_confidence_patterns = {"async_foreach", "invalid_zod_schema", "missing_predicate_suffix", "duplicate_method_def"}

    def entity_rank_with_test_penalty(e):
        score = compute_entity_rank_score(e)
        for p in e.get("_patterns", []):
            if p["type"] in lang_pattern_types:
                score += 0.5
                break
        if is_test_file(e.get("file_path", "")):
            score -= 0.3
        return score

    sorted_entities = sorted(all_entities, key=entity_rank_with_test_penalty, reverse=True)[:30]

    entity_names_lower = {e.get("entity_name", "").lower() for e in all_entities if e.get("entity_name")}
    entity_content_map = {}
    for e in all_entities:
        name = e.get("entity_name", "")
        if name:
            content = (e.get("before_content", "") or "") + (e.get("after_content", "") or "")
            entity_content_map[name.lower()] = content

    # Build entity context
    entity_parts = []
    for i, e in enumerate(sorted_entities):
        name = e.get("entity_name", "?")
        etype = e.get("entity_type", "?")
        fpath = e.get("file_path", "?")
        change = e.get("change_type", "?")
        char_limit = 1500 if i < 10 else 1000
        before = (e.get("before_content", "") or "")[:char_limit]
        after = (e.get("after_content", "") or "")[:char_limit]
        pats = ", ".join(p["type"] for p in e.get("_patterns", []))
        entity_parts.append(f"**`{name}`** ({etype}) in {fpath} [{change}]{' patterns: ' + pats if pats else ''}\nBEFORE:\n```\n{before}\n```\nAFTER:\n```\n{after}\n```")
    entity_context = "\n\n".join(entity_parts) if entity_parts else "(no entity data)"

    # Deterministic candidates
    deterministic_candidates = []
    for ent in entities_with_findings:
        name = ent.get("entity_name", "?")
        fpath = ent.get("file_path", "?")
        if is_test_file(fpath):
            continue
        for pat in ent["_patterns"]:
            if pat["type"] in lang_pattern_types:
                deterministic_candidates.append({
                    "file": fpath, "entity": name,
                    "description": f"In `{fpath}`, `{name}`: {pat['description']}",
                    "_deterministic": True, "_pattern_type": pat["type"],
                })

    non_lang_candidates = [c for c in candidates if not any(lt in c for lt in ("forEach with async", "=== comparing", "Optional.get()", "mutable", "defined multiple times", "case normalization", "lightness change", "frozen string", "missing key prop", "only 'pass'", "double-checked locking", "'end if'", "missing ? suffix", "non-deterministic", "broad exception", "vendor prefix", "Zod", "nil check", "typo in identifier", "return type annotation"))]
    hint_text = ""
    if non_lang_candidates:
        hint_text = "\n## Static analysis hints (may contain false positives):\n" + "\n".join(f"- {c}" for c in non_lang_candidates[:25])

    print(f"[{len(all_entities)}ent,{total_findings}pat,{len(cross_findings)}xref,{len(typo_findings)}typo,{len(import_findings)}imp", end="", flush=True)
    if refactor_dropped:
        print(f",-{refactor_dropped}sys", end="", flush=True)
    print("]", end="", flush=True)

    # === PHASE 2: 5 parallel LLM calls (2 general + 3 specialized) ===
    llm_timeout = 300 if provider == "anthropic" else 180

    general_prompt = f"""PR Title: {pr_title}

## Changed entities with before/after code:
{entity_context}
{hint_text}

## Full PR Diff:
{truncated}

---
Find bugs INTRODUCED by this PR. Check these categories:

1. Wrong variable/key/parameter (checking X but should check Y, passing wrong argument)
2. Null/undefined safety: removed null checks, new paths that receive null/None/nil
3. API contract breaks: signature changed but callers not updated
4. Race conditions: shared mutable state without synchronization
5. Wrong return value or type (returns wrong variable, wrong status code)
6. Security: XSS, injection, missing validation, case-sensitivity bypass
7. Missing imports: referencing types that weren't imported
8. Dead code: computed results discarded, unreachable branches
9. Test issues: flaky timing, wrong assertions, monkeypatch side effects
10. Off-by-one, wrong index/substring bounds
11. Falsy value bugs: 0 or 0.0 treated as falsy when it's valid
12. Localization: wrong language, Traditional vs Simplified Chinese

For each bug, name the EXACT file path and entity (function/method/class name).
ONLY report bugs introduced by THIS PR. Not style, not pre-existing.
Report 0-7 bugs. High confidence only.

Respond with ONLY a JSON array (no wrapping object):
[{{"file": "path/to/file.ext", "entity": "functionName", "description": "what breaks"}}]
If no bugs: []"""

    # Specialized lenses see the same entity context
    contracts_prompt = f"""PR Title: {pr_title}

## Changed entities with before/after code:
{entity_context}

## Full PR Diff:
{truncated}

---
Focus ONLY on API CONTRACT violations in this PR:
- Function signature changed but callers not updated (wrong number of args, wrong types)
- Interface/type changed but implementations don't match
- Return type changed but callers don't handle new type
- Method renamed but references still use old name
- Parameter order changed

For each entity, compare BEFORE vs AFTER carefully. Check if callers in the diff match.
Report 0-5 issues. ONLY concrete contract breaks you can verify in the diff.

Respond with ONLY a JSON array:
[{{"file": "path/to/file.ext", "entity": "functionName", "description": "what breaks"}}]
If no issues: []"""

    nullsafety_prompt = f"""PR Title: {pr_title}

## Changed entities with before/after code:
{entity_context}

## Full PR Diff:
{truncated}

---
Focus ONLY on NULL SAFETY and MISSING CHECKS in this PR:
- Null/optional check that existed in BEFORE but is missing in AFTER
- New code paths that receive nullable values without checking
- Optional chaining (?.) removed
- Guard clauses removed
- Type narrowing removed
- Default value removed

For each entity, compare BEFORE vs AFTER carefully. Look for removed safety.
Report 0-5 issues. ONLY where null/undefined WILL actually be reached.

Respond with ONLY a JSON array:
[{{"file": "path/to/file.ext", "entity": "functionName", "description": "what breaks"}}]
If no issues: []"""

    data_prompt = f"""PR Title: {pr_title}

## Changed entities with before/after code:
{entity_context}

## Full PR Diff:
{truncated}

---
Focus ONLY on DATA CORRECTNESS issues in this PR:
- Wrong variable used (checking X but should check Y)
- Wrong key/field name in object access
- Wrong comparison (== vs ===, < vs <=, && vs ||)
- Copy-paste error (same value used where different value needed)
- Wrong string/constant/enum value
- Wrong index or offset
- Swapped arguments in function call

For each entity, compare BEFORE vs AFTER. Find where data flows incorrectly.
Report 0-5 issues. ONLY concrete data errors.

Respond with ONLY a JSON array:
[{{"file": "path/to/file.ext", "entity": "functionName", "description": "what breaks"}}]
If no issues: []"""

    def parse_structured_response(content: str) -> list[dict]:
        content = content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        parsed = json.loads(content)
        if isinstance(parsed, list):
            items = parsed
        elif isinstance(parsed, dict) and "issues" in parsed:
            items = parsed["issues"]
        else:
            return []
        normalized = []
        for item in items:
            if isinstance(item, str):
                normalized.append({"file": "", "entity": "", "description": item})
            elif isinstance(item, dict):
                normalized.append({
                    "file": item.get("file", ""),
                    "entity": item.get("entity", ""),
                    "description": item.get("description", str(item)),
                })
        return normalized

    llm_issues = []
    try:
        tasks = [
            asyncio.wait_for(client.chat.completions.create(
                model=model,
                messages=[{"role": "system", "content": "You are a code reviewer. Name exact files and functions. Only report bugs you are certain about. Respond with ONLY a JSON array."},
                          {"role": "user", "content": general_prompt}],
                temperature=0.0, seed=42,
            ), timeout=llm_timeout),
            asyncio.wait_for(client.chat.completions.create(
                model=model,
                messages=[{"role": "system", "content": "You are a meticulous code reviewer. Find bugs that cause crashes, wrong results, or security issues. Focus on subtle issues easy to miss: wrong variables, missing edge cases, type errors. Respond with ONLY a JSON array."},
                          {"role": "user", "content": general_prompt}],
                temperature=0.3, seed=123,
            ), timeout=llm_timeout),
            asyncio.wait_for(client.chat.completions.create(
                model=model,
                messages=[{"role": "system", "content": "You are an API contracts reviewer. Only report concrete contract violations. Respond with ONLY a JSON array."},
                          {"role": "user", "content": contracts_prompt}],
                temperature=0.0, seed=42,
            ), timeout=llm_timeout),
            asyncio.wait_for(client.chat.completions.create(
                model=model,
                messages=[{"role": "system", "content": "You review code for null safety and missing checks. Only report real null dereference risks. Respond with ONLY a JSON array."},
                          {"role": "user", "content": nullsafety_prompt}],
                temperature=0.0, seed=42,
            ), timeout=llm_timeout),
            asyncio.wait_for(client.chat.completions.create(
                model=model,
                messages=[{"role": "system", "content": "You review code for data correctness. Only report wrong variables, wrong comparisons, wrong values. Respond with ONLY a JSON array."},
                          {"role": "user", "content": data_prompt}],
                temperature=0.0, seed=42,
            ), timeout=llm_timeout),
        ]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        for r in results:
            if isinstance(r, Exception):
                print(f"[t-err:{r.__class__.__name__}]", end="", flush=True)
            else:
                llm_issues.extend(parse_structured_response(r.choices[0].message.content))
    except Exception as e:
        print(f"[llm-err:{e.__class__.__name__}]", end="", flush=True)

    print(f"[{len(llm_issues)}llm]", end="", flush=True)

    if deterministic_candidates:
        print(f"[+{len(deterministic_candidates)}det]", end="", flush=True)

    all_candidates = llm_issues + deterministic_candidates
    if not all_candidates:
        return []

    # === PHASE 3: Deterministic scoring (same as v3) ===
    seen = set()
    deduped = []
    for issue in all_candidates:
        key = issue["description"].lower()[:80]
        if key not in seen:
            deduped.append(issue)
            seen.add(key)

    scored = []
    for issue in deduped:
        result = verify_issue_deterministic(issue, entity_names_lower, diff_files_lower, entity_content_map)
        if issue.get("_deterministic"):
            if issue.get("_pattern_type") in _high_confidence_patterns:
                result["score"] += 2
            else:
                result["score"] += 1
        scored.append(result)

    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl", ".scss", ".css", ".properties"}
        filtered = []
        dropped = 0
        for v in scored:
            text = v["description"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in diff_files_lower:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(v)
        if dropped:
            print(f"[-{dropped}f]", end="", flush=True)
        scored = filtered

    spec_phrases = ["could potentially", "might lead", "this is likely correct", "if any code relied", "hypothetically"]
    scored = [v for v in scored if not any(p in v["description"].lower() for p in spec_phrases)]

    scored.sort(key=lambda x: x["score"], reverse=True)
    to_verify = scored[:9]

    if not to_verify:
        return []

    # === PHASE 4: LLM verification + discovery (same as v3) ===
    candidates_list = "\n".join(f"{i+1}. {v['description']}" for i, v in enumerate(to_verify))

    verify_prompt = f"""PR Title: {pr_title}

## Candidate issues:
{candidates_list}

## Full PR Diff:
{truncated}

---
STEP 1: Verify each candidate against the actual diff:
1. Does the specific code mentioned actually exist in the diff? If not, DROP it.
2. Is this a concrete bug that WILL cause wrong behavior? If speculative, DROP it.
3. Is the old behavior being clearly replaced by new code elsewhere in the diff? If clearly yes, DROP it.
4. Is this about style, naming, or best practices rather than correctness? If so, DROP it.

STEP 2: Check the diff for any important bugs NOT in the candidate list. Look for:
- Wrong variable or parameter used
- Null safety removed
- API contract broken (signature changed, callers not updated)
- Wrong return value or type

Return ONLY confirmed real bugs (both verified candidates and newly found). For each, give a clear description naming the function, file, and exact failure.

Respond with ONLY: {{"issues": ["description1", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are doing final verification of code review findings. Only keep issues you can confirm against the diff. Always respond with valid JSON."},
                    {"role": "user", "content": verify_prompt},
                ],
                temperature=0.0, seed=42,
            ),
            timeout=llm_timeout,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        verified = json.loads(content).get("issues", [])
        verified = [i for i in verified if isinstance(i, str)]
    except Exception as e:
        print(f"[vfy-err:{e.__class__.__name__}]", end="", flush=True)
        verified = [v["description"] for v in to_verify[:5]]

    spec_phrases = ["could potentially", "might lead", "this is likely correct", "if any code relied", "hypothetically"]
    verified = [v for v in verified if not any(p in v.lower() for p in spec_phrases)]

    seen_final = set()
    deduped_final = []
    for v in verified:
        key = v.lower()[:80]
        if key not in seen_final:
            deduped_final.append(v)
            seen_final.add(key)

    print(f"[{len(deduped_final)}fin]", end="", flush=True)
    return deduped_final[:7]


async def review_annotated_v1(pr_title: str, diff: str, triage_section: str, client, entities: list[dict] = None) -> list[str]:
    """Strategy: annotated_v1 - v19 baseline + entity graph annotations alongside raw diff.
    Same 9 lenses, same structural filter, same validation.
    Replaces build_rich_triage with build_entity_annotations (risk scores, blast radius, dependents, dependencies)."""
    model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    truncated = truncate_diff(diff, max_chars=80000)
    annotations = build_entity_annotations(entities) if entities else triage_section

    # Extract diff file paths for structural filter
    diff_files = set()
    for line in diff.split("\n"):
        if line.startswith("+++ b/") or line.startswith("--- a/"):
            path = line.split("/", 1)[1] if "/" in line else line[6:]
            if path and path != "/dev/null":
                diff_files.add(path)
                diff_files.add(path.rsplit("/", 1)[-1])

    async def run_lens(system_msg: str, prompt: str, temp: float, seed: int = 42) -> list[dict]:
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": system_msg},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=temp,
                    seed=seed,
                ),
                timeout=180,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            items = json.loads(content).get("issues", [])
            result = []
            for item in items:
                if isinstance(item, str):
                    result.append({"issue": item, "evidence": ""})
                elif isinstance(item, dict):
                    result.append({"issue": item.get("issue", str(item)), "evidence": item.get("evidence", "")})
            return result
        except Exception as e:
            print(f"[lens-err:{e}]", end="", flush=True)
            return []

    prompt_data = f"""You are a code reviewer specializing in DATA CORRECTNESS issues.

PR Title: {pr_title}
{annotations}
PR Diff:
{truncated}

Focus ONLY on: wrong translations, wrong constants/mappings/enum values, copy-paste errors, wrong key/field references, case sensitivity in comparisons, incorrect regex.
Rules: ONLY concrete data issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_concurrency = f"""You are a code reviewer specializing in CONCURRENCY and STATE bugs.

PR Title: {pr_title}
{annotations}
PR Diff:
{truncated}

Focus ONLY on: race conditions, missing locks/transactions, stale reads, process lifecycle bugs, cache inconsistency, feature flag inconsistency.
Rules: ONLY issues with evidence in the diff. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_contracts = f"""You are a code reviewer specializing in API CONTRACT violations.

PR Title: {pr_title}
{annotations}
PR Diff:
{truncated}

Focus ONLY on: missing abstract method implementations, wrong signatures/types, API breaking changes, wrong parameter order, key mismatches, missing React keys, import errors, method name typos breaking interfaces.
Rules: ONLY verifiable issues. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_security = f"""You are a security-focused code reviewer.

PR Title: {pr_title}
{annotations}
PR Diff:
{truncated}

Focus ONLY on: SSRF, XSS, injection, auth bypass, origin/referrer bypass, case sensitivity bypass in security comparisons, frame options misconfig, hardcoded secrets.
Rules: ONLY real exploitable vulnerabilities. Be specific. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_typos = f"""You are a code reviewer with exceptional attention to character-level detail.

PR Title: {pr_title}
{annotations}
PR Diff:
{truncated}

Focus ONLY on:
- Method/function/variable name TYPOS causing runtime errors
- Wrong language in locale/translation files
- Missing required method suffixes (Rails '?', etc.)
- Case sensitivity bugs in comparisons
- Wrong vendor prefixes
- Property/key name mismatches

Rules: Character-level precision. Only if it causes runtime failure. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_runtime = f"""You are a code reviewer focused on RUNTIME FAILURES.

PR Title: {pr_title}
{annotations}
PR Diff:
{truncated}

For each changed function/class, ask: "What would happen if I ran this code?"

Focus ONLY on:
- Null/nil/undefined dereference
- Missing abstract method implementations causing TypeError
- Unreachable code branches
- Infinite recursion without termination
- Wrong error messages
- Panic on nil in Go
- Missing React keys

Rules: RUNTIME behavior only. Only actual failures. Max 5 issues.
Respond with ONLY: {{"issues": [{{"issue": "desc", "evidence": "code"}}]}}"""

    prompt_general = PROMPT_DEEP.format(pr_title=pr_title, triage_section=annotations, diff=truncated)
    sys_precise = "You are a precise code reviewer. Only report real bugs you are confident about. Always respond with valid JSON."

    # 9 lenses: 6 specialized@T=0 + 1 general@T=0 + 2 general@T=0.3 (different seeds)
    results = await asyncio.gather(
        run_lens("You are a data correctness reviewer. Always respond with valid JSON.", prompt_data, 0.0),
        run_lens("You are a concurrency/state bug reviewer. Always respond with valid JSON.", prompt_concurrency, 0.0),
        run_lens("You are an API contracts reviewer. Always respond with valid JSON.", prompt_contracts, 0.0),
        run_lens("You are a security reviewer. Always respond with valid JSON.", prompt_security, 0.0),
        run_lens("You are a character-level detail reviewer. Always respond with valid JSON.", prompt_typos, 0.0),
        run_lens("You are a runtime failure analyst. Always respond with valid JSON.", prompt_runtime, 0.0),
        run_lens(sys_precise, prompt_general, 0.0),
        run_lens(sys_precise, prompt_general, 0.3, seed=42),
        run_lens(sys_precise, prompt_general, 0.3, seed=123),
    )

    # Merge + dedup
    all_issues = []
    existing_lower = set()
    for pass_result in results:
        for s in pass_result:
            key = s["issue"].lower()[:80]
            if key not in existing_lower:
                all_issues.append(s)
                existing_lower.add(key)

    if not all_issues:
        return []

    # Structural file filter
    if diff_files:
        code_exts = {".py", ".js", ".ts", ".tsx", ".jsx", ".java", ".go", ".rs", ".rb", ".c", ".cpp", ".cs", ".swift", ".kt", ".scala", ".hbs", ".erb", ".ex", ".exs", ".hcl"}
        filtered = []
        dropped = 0
        for s in all_issues:
            text = s["issue"].lower()
            has_phantom_file = False
            for word in text.replace("/", " / ").split():
                if any(word.endswith(ext) for ext in code_exts):
                    base = word.rsplit("/", 1)[-1]
                    if base not in {f.lower().rsplit("/", 1)[-1] for f in diff_files}:
                        has_phantom_file = True
                        break
            if has_phantom_file:
                dropped += 1
            else:
                filtered.append(s)
        if dropped:
            print(f"[-{dropped}file]", end="", flush=True)
        all_issues = filtered

    if not all_issues:
        return []

    print(f"[{len(all_issues)} raw]", end="", flush=True)

    # Validate
    candidates_text = "\n".join(
        f"{i+1}. {s['issue']}" + (f"\n   Evidence: {s['evidence']}" if s['evidence'] else "")
        for i, s in enumerate(all_issues)
    )

    refine_prompt = f"""You are a senior code reviewer doing final validation. You have the PR diff and candidate issues.

PR Title: {pr_title}

PR Diff (for verification):
{truncated}

Candidate Issues:
{candidates_text}

For each candidate, verify against the actual diff:
1. Can you find the specific code that's buggy? If yes, keep it.
2. Is this a real bug that would cause incorrect behavior in production? If yes, keep it.
3. Is this about deleted/removed code being replaced? If so, DROP it.
4. Is this speculative or theoretical ("could potentially...")? If so, DROP it.
5. Is this about style, naming conventions, or missing tests? If so, DROP it.

Return ONLY the issues that are verified real bugs with evidence in the diff.

Respond with ONLY a JSON object:
{{"issues": ["verified issue 1", "verified issue 2", ...]}}"""

    try:
        response = await asyncio.wait_for(
            client.chat.completions.create(
                model=model,
                messages=[
                    {"role": "system", "content": "You are a precise reviewer. Verify each issue against the actual diff. Only keep confirmed bugs. Always respond with valid JSON."},
                    {"role": "user", "content": refine_prompt},
                ],
                temperature=0.0,
                seed=42,
            ),
            timeout=180,
        )
        content = response.choices[0].message.content.strip()
        if content.startswith("```"):
            content = content.split("```")[1]
            if content.startswith("json"):
                content = content[4:]
            content = content.strip()
        validated = json.loads(content).get("issues", [])
        return validated[:7]
    except Exception as e:
        print(f"[val-err:{e.__class__.__name__}]", end="", flush=True)
        return [s["issue"] for s in all_issues[:5]]


# Thread-local-ish hack to pass PR info to review_api without changing the strategy signature
_current_pr_info: dict = {}


class AnthropicOpenAIAdapter:
    """Wraps Anthropic AsyncAnthropic client to match OpenAI's chat.completions.create interface."""
    def __init__(self, anthropic_client):
        self._client = anthropic_client
        self.chat = self

    @property
    def completions(self):
        return self

    async def create(self, model, messages, temperature=0.0, seed=None, **kwargs):
        # Extract system message
        system_text = ""
        user_messages = []
        for msg in messages:
            if msg["role"] == "system":
                system_text = msg["content"]
            else:
                user_messages.append(msg)

        response = await self._client.messages.create(
            model=model,
            max_tokens=4096,
            system=system_text,
            messages=user_messages,
            temperature=temperature,
        )
        # Wrap response to match OpenAI shape: response.choices[0].message.content
        class _Choice:
            def __init__(self, text):
                self.message = type("obj", (), {"content": text})()
        class _Response:
            def __init__(self, text):
                self.choices = [_Choice(text)]
        return _Response(response.content[0].text)


async def step_review(strategy: str = "precise"):
    provider = os.environ.get("REVIEW_PROVIDER", "openai")

    with open(BENCHMARK_DATA) as f:
        benchmark = json.load(f)

    triage = {}
    if INSPECT_RESULTS.exists():
        with open(INSPECT_RESULTS) as f:
            triage = json.load(f)

    diff_cache = load_or_build_diff_cache(benchmark)

    # Clear previous candidates
    candidates = {}

    if provider == "anthropic":
        from anthropic import AsyncAnthropic
        raw_client = AsyncAnthropic(api_key=os.environ.get("ANTHROPIC_API_KEY"))
        client = AnthropicOpenAIAdapter(raw_client)
        model = os.environ.get("REVIEW_MODEL", "claude-sonnet-4-5-20250929")
    else:
        from openai import AsyncOpenAI
        client = AsyncOpenAI(api_key=os.environ.get("OPENAI_API_KEY"))
        model = os.environ.get("REVIEW_MODEL", "gpt-5.2")
    print(f"Strategy: {strategy}, Model: {model}, Provider: {provider}")

    strategies = {"precise": review_precise, "two_pass": review_two_pass, "targeted": review_targeted, "targeted_validated": review_targeted_validated, "entity_focused": review_entity_focused, "consensus": review_consensus, "deep": review_deep, "deep_v2": review_deep_v2, "deep_v3": review_deep_v3, "deep_v4": review_deep_v4, "deep_v5": review_deep_v5, "deep_v6": review_deep_v6, "deep_v7": review_deep_v7, "deep_v8": review_deep_v8, "deep_v9": review_deep_v9, "deep_v10": review_deep_v10, "deep_v11": review_deep_v11, "deep_v12": review_deep_v12, "deep_v13": review_deep_v13, "deep_v14": review_deep_v14, "deep_v17": review_deep_v17, "deep_v18": review_deep_v18, "deep_v19": review_deep_v19, "deep_v20": review_deep_v20, "deep_v21": review_deep_v21, "deep_v22": review_deep_v22, "deep_v23": review_deep_v23, "deep_v24": review_deep_v24, "deep_v25": review_deep_v25, "deep_v26": review_deep_v26, "deep_v27": review_deep_v27, "deep_v28": review_deep_v28, "deep_v29": review_deep_v29, "deep_v30": review_deep_v30, "deep_v31": review_deep_v31, "deep_v32": review_deep_v32, "deep_v33": review_deep_v33, "deep_v34": review_deep_v34, "deep_v35": review_deep_v35, "deep_v36": review_deep_v36, "deep_v38": review_deep_v38, "deep_v40": review_deep_v40, "deep_v50": review_deep_v50, "deep_v60": review_deep_v60, "deep_v70": review_deep_v70, "deep_v80": review_deep_v80, "deep_v90": review_deep_v90, "deep_v100": review_deep_v100, "deep_v110": review_deep_v110, "deep_v120": review_deep_v120, "deep_v130": review_deep_v130, "deep_v140": review_deep_v140, "deep_v150": review_deep_v150, "deep_v160": review_deep_v160, "deep_v170": review_deep_v170, "deep_v180": review_deep_v180, "deep_v190": review_deep_v190, "deep_v200": review_deep_v200, "deep_v210": review_deep_v210, "deep_v220": review_deep_v220, "deep_v230": review_deep_v230, "deep_v240": review_deep_v240, "deep_v250": review_deep_v250, "deep_v260": review_deep_v260, "deep_v270": review_deep_v270, "deep_v280": review_deep_v280, "deterministic_v1": review_deterministic_v1, "deterministic_v2": review_deterministic_v2, "deterministic_v3": review_deterministic_v3, "deterministic_v4": review_deterministic_v4, "entity_only_v1": review_entity_only_v1, "entity_only_v2": review_entity_only_v2, "annotated_v1": review_annotated_v1, "hybrid_v1": review_hybrid_v1, "hybrid_v2": review_hybrid_v2, "hybrid_v3": review_hybrid_v3, "hybrid_v4": review_hybrid_v4, "hybrid_v5": review_hybrid_v5, "hybrid_v6": review_hybrid_v6, "hybrid_v7": review_hybrid_v7, "hybrid_v8": review_hybrid_v8, "hybrid_v9": review_hybrid_v9, "hybrid_v10": review_hybrid_v10, "hybrid_v11": review_hybrid_v11, "hybrid_v12": review_hybrid_v12, "hybrid_v13": review_hybrid_v13, "predictive_v1": review_predictive_v1, "api": review_api}
    review_fn = strategies.get(strategy, review_precise)
    needs_entities = strategy in ("entity_focused", "deep", "deep_v2", "deep_v3", "deep_v4", "deep_v5", "deep_v6", "deep_v7", "deep_v8", "deep_v9", "deep_v10", "deep_v11", "deep_v12", "deep_v13", "deep_v14", "deep_v17", "deep_v18", "deep_v19", "deep_v20", "deep_v21", "deep_v22", "deep_v23", "deep_v24", "deep_v25", "deep_v26", "deep_v27", "deep_v28", "deep_v29", "deep_v30", "deep_v31", "deep_v32", "deep_v33", "deep_v34", "deep_v35", "deep_v36", "deep_v38", "deep_v40", "deep_v50", "deep_v60", "deep_v70", "deep_v80", "deep_v90", "deep_v100", "deep_v110", "deep_v120", "deep_v130", "deep_v140", "deep_v150", "deep_v160", "deep_v170", "deep_v180", "deep_v190", "deep_v200", "deep_v210", "deep_v220", "deep_v230", "deep_v240", "deep_v250", "deep_v260", "deep_v270", "deep_v280", "deterministic_v1", "deterministic_v2", "deterministic_v3", "deterministic_v4", "entity_only_v1", "entity_only_v2", "annotated_v1", "hybrid_v1", "hybrid_v2", "hybrid_v3", "hybrid_v4", "hybrid_v5", "hybrid_v6", "hybrid_v7", "hybrid_v8", "hybrid_v9", "hybrid_v10", "hybrid_v11", "hybrid_v12", "hybrid_v13", "predictive_v1")
    needs_deps = strategy in ("deep_v80", "deep_v90", "deep_v100", "deep_v110", "deep_v120")

    # Build dependency cache if needed
    dep_cache_data = {}
    if needs_deps:
        if strategy in ("deep_v90", "deep_v100", "deep_v110", "deep_v120"):
            print("Building wide dependency cache (repo-wide callers)...")
            dep_cache_data = build_wide_dep_cache(benchmark, diff_cache)
        else:
            print("Building dependency cache from sem graph...")
            dep_cache_data = build_dep_cache(benchmark, diff_cache)

    for i, (url, entry) in enumerate(benchmark.items()):
        info = extract_pr_info(url)
        if not info:
            candidates[url] = []
            continue

        owner_repo, pr_number = info
        pr_title = entry.get("pr_title", "")
        entities = triage.get(url, {}).get("entity_reviews", [])
        triage_section = build_triage_section(entities)
        diff = diff_cache.get(url, "")

        if not diff:
            print(f"[{i+1}/{len(benchmark)}] {owner_repo}/#{pr_number} no diff")
            candidates[url] = []
            continue

        print(f"[{i+1}/{len(benchmark)}] {owner_repo}/#{pr_number}...", end=" ", flush=True)

        # Set PR info for review_api strategy
        _current_pr_info["owner_repo"] = owner_repo
        _current_pr_info["pr_number"] = pr_number

        if needs_deps:
            pr_dep_data = dict(dep_cache_data.get(url, {}))  # copy to avoid mutation
            if strategy in ("deep_v120",):
                pr_dep_data["_pr_url"] = url
            issues = await review_fn(pr_title, diff, triage_section, client, entities=entities, dep_data=pr_dep_data)
        elif needs_entities:
            issues = await review_fn(pr_title, diff, triage_section, client, entities=entities)
        else:
            issues = await review_fn(pr_title, diff, triage_section, client)
        print(f"{len(issues)} issues")
        candidates[url] = issues

        # Save pipeline debug stages if available
        if hasattr(review_fn, '_last_debug'):
            if not hasattr(step_review, '_debug_all'):
                step_review._debug_all = {}
            step_review._debug_all[url] = review_fn._last_debug

        with open(INSPECT_CANDIDATES, "w") as f:
            json.dump(candidates, f, indent=2)

    total = sum(len(c) for c in candidates.values())
    print(f"\nDone. {total} total candidates. Saved to {INSPECT_CANDIDATES}")

    # Save pipeline debug data
    if hasattr(step_review, '_debug_all'):
        debug_path = OUTPUT_DIR / "pipeline_debug.json"
        with open(debug_path, "w") as f:
            json.dump(step_review._debug_all, f, indent=2)
        print(f"Pipeline debug saved to {debug_path}")

    # Save pre-validation candidates for diagnostic (if available)
    if _PRE_VAL_CANDIDATES:
        pre_val_path = OUTPUT_DIR / "pre_validation_candidates.json"
        # Map pr_title -> pr_url for proper keying
        pre_val_by_url = {}
        for url, entry in benchmark.items():
            title = entry.get("pr_title", "")
            if title in _PRE_VAL_CANDIDATES:
                pre_val_by_url[url] = _PRE_VAL_CANDIDATES[title]
        with open(pre_val_path, "w") as f:
            json.dump(pre_val_by_url, f, indent=2)
        pre_total = sum(len(c) for c in pre_val_by_url.values())
        print(f"Pre-validation candidates: {pre_total} saved to {pre_val_path}")


async def judge_one(golden_comment: str, candidate: str, client) -> dict:
    prompt = JUDGE_PROMPT.format(golden_comment=golden_comment, candidate=candidate)
    model = os.environ.get("JUDGE_MODEL", "gpt-5.2")
    for attempt in range(3):
        try:
            response = await asyncio.wait_for(
                client.chat.completions.create(
                    model=model,
                    messages=[
                        {"role": "system", "content": "You are a precise code review evaluator. Always respond with valid JSON."},
                        {"role": "user", "content": prompt},
                    ],
                    temperature=0.0,
                    seed=42,
                ),
                timeout=30,
            )
            content = response.choices[0].message.content.strip()
            if content.startswith("```"):
                content = content.split("```")[1]
                if content.startswith("json"):
                    content = content[4:]
                content = content.strip()
            return json.loads(content)
        except Exception as e:
            if attempt < 2:
                await asyncio.sleep(1 * (attempt + 1))
                continue
            return {"error": str(e)}


async def evaluate_pr(golden_comments: list[dict], candidates: list[str], client) -> dict:
    if not golden_comments:
        return {"skipped": True, "reason": "No golden comments"}

    if not candidates:
        return {
            "skipped": False,
            "true_positives": [], "false_positives": [],
            "false_negatives": [{"golden_comment": gc["comment"], "severity": gc.get("severity")} for gc in golden_comments],
            "total_candidates": 0, "total_golden": len(golden_comments),
            "tp": 0, "fp": 0, "fn": len(golden_comments),
            "precision": 0.0, "recall": 0.0,
        }

    tasks = []
    meta = []
    for gc in golden_comments:
        for cand in candidates:
            tasks.append(judge_one(gc["comment"], cand, client))
            meta.append({"golden": gc["comment"], "severity": gc.get("severity"), "candidate": cand})

    results = []
    for i in range(0, len(tasks), 40):
        batch = tasks[i:i+40]
        batch_results = await asyncio.gather(*batch, return_exceptions=True)
        results.extend(batch_results)
        if i + 40 < len(tasks):
            await asyncio.sleep(0.5)

    golden_matched = {}
    for gc in golden_comments:
        golden_matched[gc["comment"]] = {"severity": gc.get("severity"), "matched": False, "best_confidence": 0.0, "matched_candidate": None}
    candidate_matched = dict.fromkeys(candidates, False)

    for i, result in enumerate(results):
        m = meta[i]
        if isinstance(result, Exception):
            continue
        if result.get("error"):
            continue
        if result.get("match") and result.get("confidence", 0) > golden_matched[m["golden"]]["best_confidence"]:
            golden_matched[m["golden"]]["matched"] = True
            golden_matched[m["golden"]]["best_confidence"] = result["confidence"]
            golden_matched[m["golden"]]["matched_candidate"] = m["candidate"]
            golden_matched[m["golden"]]["reasoning"] = result.get("reasoning")
            candidate_matched[m["candidate"]] = True

    tp_list = []
    fn_list = []
    for golden, info in golden_matched.items():
        if info["matched"]:
            tp_list.append({"golden_comment": golden, "severity": info["severity"], "matched_candidate": info["matched_candidate"], "confidence": info["best_confidence"]})
        else:
            fn_list.append({"golden_comment": golden, "severity": info["severity"]})

    fp_list = [{"candidate": c} for c, matched in candidate_matched.items() if not matched]
    tp = len(tp_list)
    total_cand = len(candidates)
    total_golden = len(golden_comments)

    return {
        "skipped": False,
        "true_positives": tp_list, "false_positives": fp_list, "false_negatives": fn_list,
        "total_candidates": total_cand, "total_golden": total_golden,
        "tp": tp, "fp": len(fp_list), "fn": len(fn_list),
        "precision": tp / total_cand if total_cand > 0 else 0.0,
        "recall": tp / total_golden if total_golden > 0 else 0.0,
    }


async def step_judge():
    from openai import AsyncOpenAI

    if not INSPECT_CANDIDATES.exists():
        print("Run 'review' step first")
        return

    with open(BENCHMARK_DATA) as f:
        benchmark = json.load(f)
    with open(INSPECT_CANDIDATES) as f:
        candidates = json.load(f)

    evaluations = {}

    client = AsyncOpenAI(api_key=os.environ.get("OPENAI_API_KEY"))
    model = os.environ.get("JUDGE_MODEL", "gpt-5.2")
    print(f"Judge model: {model}")

    for i, (url, entry) in enumerate(benchmark.items()):
        golden = entry.get("golden_comments", [])
        cands = candidates.get(url, [])

        print(f"[{i+1}/50] {url.split('/')[-3]}/#{url.split('/')[-1]} ({len(golden)}g/{len(cands)}c)...", end=" ", flush=True)

        result = await evaluate_pr(golden, cands, client)
        print(f"tp={result.get('tp',0)} fp={result.get('fp',0)} fn={result.get('fn',0)}")

        evaluations[url] = result

        with open(INSPECT_EVALUATIONS, "w") as f:
            json.dump(evaluations, f, indent=2)

    # Aggregate
    total_tp = sum(e.get("tp", 0) for e in evaluations.values() if not e.get("skipped"))
    total_fp = sum(e.get("fp", 0) for e in evaluations.values() if not e.get("skipped"))
    total_fn = sum(e.get("fn", 0) for e in evaluations.values() if not e.get("skipped"))
    total_cand = sum(e.get("total_candidates", 0) for e in evaluations.values() if not e.get("skipped"))
    total_golden = sum(e.get("total_golden", 0) for e in evaluations.values() if not e.get("skipped"))

    precision = total_tp / (total_tp + total_fp) if (total_tp + total_fp) > 0 else 0
    recall = total_tp / (total_tp + total_fn) if (total_tp + total_fn) > 0 else 0
    f1 = 2 * precision * recall / (precision + recall) if (precision + recall) > 0 else 0

    print(f"\n{'='*60}")
    print(f"RESULTS")
    print(f"{'='*60}")
    print(f"PRs:        {len(evaluations)}")
    print(f"Golden:     {total_golden}")
    print(f"Candidates: {total_cand}")
    print(f"TP:         {total_tp}")
    print(f"FP:         {total_fp}")
    print(f"FN:         {total_fn}")
    print(f"Precision:  {precision:.1%}")
    print(f"Recall:     {recall:.1%}")
    print(f"F1:         {f1:.1%}")

    # Leaderboard comparison
    leaderboard = [
        ("Augment", 45.8, 37.3, 59.1),
        ("GitHub Copilot", 32.6, 23.5, 53.3),
        ("Cursor Bugbot", 40.5, 38.3, 43.1),
        ("Qodo", 30.1, 23.4, 42.3),
        ("CodeRabbit", 28.1, 21.2, 41.6),
        ("Claude Code", 33.6, 30.5, 37.2),
        ("Propel", 38.1, 38.9, 37.2),
        ("Greptile", 35.1, 33.8, 36.5),
        ("Gemini", 28.1, 24.6, 32.8),
        ("Baz", 30.3, 34.6, 27.0),
        ("Kilo+Grok", 25.0, 48.9, 16.8),
    ]
    leaderboard.append(("inspect+LLM", round(f1*100,1), round(precision*100,1), round(recall*100,1)))
    leaderboard.sort(key=lambda x: x[1], reverse=True)

    print(f"\n{'='*60}")
    print(f"LEADERBOARD")
    print(f"{'='*60}")
    print(f"{'#':<4} {'Tool':<20} {'F1':>8} {'Prec':>8} {'Recall':>8}")
    print(f"{'-'*48}")
    for rank, (tool, f1_s, p, r) in enumerate(leaderboard, 1):
        marker = " <<<" if tool == "inspect+LLM" else ""
        print(f"#{rank:<3} {tool:<20} {f1_s:>7.1f}% {p:>7.1f}% {r:>7.1f}%{marker}")


def ensure_repo_clone(owner_repo: str) -> Path:
    """Clone repo if not already cloned. Returns repo path."""
    dir_name = REPO_DIR_MAP.get(owner_repo, owner_repo.split("/")[-1])
    repo_dir = REPOS_DIR / dir_name
    if repo_dir.exists():
        return repo_dir
    REPOS_DIR.mkdir(parents=True, exist_ok=True)
    print(f"  Cloning {owner_repo}...")
    subprocess.run(
        ["git", "clone", "--filter=blob:none", f"https://github.com/{owner_repo}.git", str(repo_dir)],
        check=True, capture_output=True, text=True,
    )
    return repo_dir


def run_inspect_local(owner_repo: str, pr_number: int, repo_dir: Path, include_dependents: bool = False) -> dict | None:
    """Run inspect diff locally with full graph analysis.
    Uses merge-base to get the same diff scope as GitHub's PR view.
    Filters entities using GitHub's PR file list to avoid merge-base artifacts."""
    try:
        # Get base ref and head SHA from GitHub API
        base_result = subprocess.run(
            ["gh", "api", f"repos/{owner_repo}/pulls/{pr_number}", "--jq", ".base.sha + \" \" + .head.sha"],
            capture_output=True, text=True, timeout=30,
        )
        if base_result.returncode != 0:
            print(f"  gh api failed: {base_result.stderr[:100]}")
            return None
        parts = base_result.stdout.strip().split()
        if len(parts) != 2:
            print(f"  bad gh output: {base_result.stdout[:100]}")
            return None
        base_sha, head_sha = parts

        # Get PR file list with statuses from GitHub (the source of truth for what the PR changes)
        files_result = subprocess.run(
            ["gh", "api", f"repos/{owner_repo}/pulls/{pr_number}/files", "--paginate",
             "--jq", '.[] | .filename + "\\t" + .status'],
            capture_output=True, text=True, timeout=30,
        )
        pr_file_status = {}  # filename -> "added"|"modified"|"removed"|"renamed"
        if files_result.returncode == 0:
            for line in files_result.stdout.strip().split("\n"):
                if "\t" in line:
                    fname, status = line.split("\t", 1)
                    pr_file_status[fname] = status

        # Fetch both SHAs
        subprocess.run(
            ["git", "fetch", "origin", base_sha, head_sha],
            cwd=repo_dir, check=True, capture_output=True, text=True, timeout=120,
        )
        # Checkout head so graph is built from head state
        subprocess.run(
            ["git", "checkout", head_sha],
            cwd=repo_dir, check=True, capture_output=True, text=True, timeout=30,
        )
        # Use base_sha..head_sha (not merge-base). The PR file filter handles scoping.
        # base_sha is the base branch HEAD, so files that exist there correctly show as
        # "modified" instead of "added" (which happened with old merge-base).
        cmd = [str(INSPECT_BIN), "diff", f"{base_sha}..{head_sha}", "-C", str(repo_dir), "--format", "json"]
        if include_dependents:
            cmd.append("--dependents")
        result = subprocess.run(
            cmd,
            capture_output=True, text=True, timeout=300,
        )
        if result.returncode != 0:
            print(f"  inspect failed: {result.stderr[:200]}")
            return None
        output = result.stdout
        json_start = output.find("{")
        if json_start == -1:
            return None
        data = json.loads(output[json_start:])

        # Filter entities to only files in the PR (base_sha..head_sha includes many
        # unrelated files from commits on the base branch). Since we use base_sha (not
        # merge-base), change_type is correct: "added" = genuinely new, "modified" = changed.
        if pr_file_status and "entity_reviews" in data:
            before_count = len(data["entity_reviews"])
            pr_files_set = set(pr_file_status.keys())
            data["entity_reviews"] = [e for e in data["entity_reviews"] if e.get("file_path", "") in pr_files_set]
            dropped = before_count - len(data["entity_reviews"])
            if dropped:
                print(f"  [{dropped} filtered]", end="", flush=True)

        return data
    except subprocess.TimeoutExpired:
        print(f"  timeout")
        return None
    except subprocess.CalledProcessError as e:
        print(f"  git error: {e.stderr[:200] if e.stderr else str(e)}")
        return None
    except json.JSONDecodeError as e:
        print(f"  JSON parse error: {e}")
        return None


def run_inspect_remote(owner_repo: str, pr_number: int) -> dict | None:
    """Run inspect pr --remote on a PR and return JSON result.
    Uses GitHub API for diffs - gets correctly scoped entities matching what GitHub shows."""
    try:
        result = subprocess.run(
            [
                str(INSPECT_BIN), "pr", str(pr_number),
                "--remote", owner_repo,
                "--format", "json",
            ],
            capture_output=True, text=True, timeout=120,
        )
        if result.returncode != 0:
            print(f"inspect-remote failed: {result.stderr[:200]}")
            return None
        output = result.stdout
        json_start = output.find("{")
        if json_start == -1:
            return None
        return json.loads(output[json_start:])
    except subprocess.TimeoutExpired:
        print(f"inspect-remote timed out")
        return None
    except json.JSONDecodeError as e:
        print(f"JSON parse error: {e}")
        return None


def augment_with_graph(remote_entities: list[dict], local_entities: list[dict]) -> int:
    """Augment remote entities with graph data from local analysis.
    Matches by (file_path, entity_name). Returns count of entities augmented."""
    # Build lookup from local entities
    local_lookup = {}
    for e in local_entities:
        key = (e.get("file_path", ""), e.get("entity_name", ""))
        if key[0] and key[1]:
            local_lookup[key] = e

    augmented = 0
    graph_fields = ["blast_radius", "dependent_count", "dependent_names", "dependency_names"]
    for e in remote_entities:
        key = (e.get("file_path", ""), e.get("entity_name", ""))
        local = local_lookup.get(key)
        if local:
            for field in graph_fields:
                val = local.get(field)
                if val:
                    e[field] = val
                    augmented += 1
    return augmented


def step_triage():
    """Run inspect triage on all 50 PRs.
    Modes (--mode flag):
      local   - full local clone + graph analysis (default)
      remote  - GitHub API, correct entity scoping, no graph
      hybrid  - remote entities + local graph augmentation
    Use --force to re-run all PRs."""
    OUTPUT_DIR.mkdir(parents=True, exist_ok=True)
    force = "--force" in sys.argv
    include_dependents = "--dependents" in sys.argv

    # Parse mode
    mode = "local"
    if "--mode" in sys.argv:
        idx = sys.argv.index("--mode")
        if idx + 1 < len(sys.argv):
            mode = sys.argv[idx + 1]

    with open(BENCHMARK_DATA) as f:
        benchmark = json.load(f)

    results = {}
    if INSPECT_RESULTS.exists() and not force:
        with open(INSPECT_RESULTS) as f:
            results = json.load(f)

    done_count = len(results) if not force else 0
    print(f"Loaded {len(benchmark)} PRs, {done_count} already triaged (mode={mode}){' (force re-run)' if force else ''}")

    for i, (url, entry) in enumerate(benchmark.items()):
        if not force and url in results:
            continue

        info = extract_pr_info(url)
        if not info:
            print(f"[{i+1}/50] SKIP bad URL: {url}")
            continue

        owner_repo, pr_number = info
        print(f"[{i+1}/50] {owner_repo} #{pr_number}...", end=" ", flush=True)

        if mode == "remote":
            result = run_inspect_remote(owner_repo, pr_number)
            if result:
                entity_count = len(result.get("entity_reviews", []))
                print(f"{entity_count} entities (remote)")
                results[url] = result
            else:
                print("failed")

        elif mode == "hybrid":
            # Step 1: Remote triage (correct entity scoping)
            remote_result = run_inspect_remote(owner_repo, pr_number)

            # Step 2: Local analysis for graph data (also serves as fallback)
            try:
                repo_dir = ensure_repo_clone(owner_repo)
                local_result = run_inspect_local(owner_repo, pr_number, repo_dir, include_dependents=include_dependents)
                local_entities = local_result.get("entity_reviews", []) if local_result else []
            except (subprocess.CalledProcessError, Exception) as e:
                local_entities = []
                local_result = None

            if remote_result:
                remote_entities = remote_result.get("entity_reviews", [])
                print(f"{len(remote_entities)}r+{len(local_entities)}l", end="", flush=True)

                # Step 3: Augment remote entities with local graph data
                aug_count = augment_with_graph(remote_entities, local_entities)
                has_graph = any(
                    e.get("blast_radius", 0) > 0 or e.get("dependent_count", 0) > 0
                    for e in remote_entities
                )
                print(f" = {len(remote_entities)} entities {'(+graph:' + str(aug_count) + ')' if has_graph else '(no graph)'}")
                results[url] = remote_result
            elif local_result:
                # Fallback to local when remote fails
                entity_count = len(local_entities)
                has_graph = any(
                    e.get("blast_radius", 0) > 0 or e.get("dependent_count", 0) > 0
                    for e in local_entities
                )
                print(f"remote failed, fallback: {entity_count} entities (local{'+ graph' if has_graph else ''})")
                results[url] = local_result
            else:
                print("both failed")

        else:  # local
            try:
                repo_dir = ensure_repo_clone(owner_repo)
            except subprocess.CalledProcessError as e:
                print(f"clone failed: {e}")
                continue

            result = run_inspect_local(owner_repo, pr_number, repo_dir, include_dependents=include_dependents)
            if result:
                entity_count = len(result.get("entity_reviews", []))
                has_graph = any(
                    e.get("blast_radius", 0) > 0 or e.get("dependent_count", 0) > 0
                    for e in result.get("entity_reviews", [])
                )
                dep_count = sum(len(e.get("dependent_entities", [])) for e in result.get("entity_reviews", []))
                dep_msg = f"+{dep_count}deps" if dep_count else ""
                print(f"{entity_count} entities {'(with graph)' if has_graph else '(no graph)'}{dep_msg}")
                results[url] = result
            else:
                print("failed")

        # Save after each PR
        with open(INSPECT_RESULTS, "w") as f:
            json.dump(results, f, indent=2)

    print(f"\nDone. {len(results)} PRs triaged. Saved to {INSPECT_RESULTS}")


async def main():
    if len(sys.argv) < 2:
        print("Usage: python martian_bench_v2.py [triage|review|judge] [--strategy precise|two_pass]")
        return

    cmd = sys.argv[1]
    strategy = "precise"
    if "--strategy" in sys.argv:
        idx = sys.argv.index("--strategy")
        if idx + 1 < len(sys.argv):
            strategy = sys.argv[idx + 1]

    if cmd == "triage":
        step_triage()
    elif cmd == "review":
        await step_review(strategy)
    elif cmd == "judge":
        await step_judge()
    elif cmd == "all":
        await step_review(strategy)
        await step_judge()
    else:
        print(f"Unknown: {cmd}")


if __name__ == "__main__":
    asyncio.run(main())
